```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Cat</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 50);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.5, 0);
controls.enableDamping = true;

// ── Lights ──
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const dirLight = new THREE.DirectionalLight(0xffeedd, 1.5);
dirLight.position.set(5, 10, 7);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x6688ff, 0.4);
rimLight.position.set(-3, 5, -5);
scene.add(rimLight);

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(15, 64),
  new THREE.MeshStandardMaterial({ color: 0x2a2a4a, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Materials ──
const furMat = new THREE.MeshStandardMaterial({ color: 0xf4a460, roughness: 0.8 });
const darkFurMat = new THREE.MeshStandardMaterial({ color: 0x8b6914, roughness: 0.8 });
const noseMat = new THREE.MeshStandardMaterial({ color: 0xff6b8a, roughness: 0.4 });
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x22cc88, roughness: 0.2, metalness: 0.3 });
const pupilMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.1 });
const whiteMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 });
const innerEarMat = new THREE.MeshStandardMaterial({ color: 0xffb6c1, roughness: 0.6 });

// ── Cat Group ──
const cat = new THREE.Group();

// Body
const body = new THREE.Mesh(new THREE.SphereGeometry(1, 32, 32), furMat);
body.scale.set(1, 0.85, 1.3);
body.position.set(0, 1.3, 0);
body.castShadow = true;
cat.add(body);

// Chest (lighter fur)
const chest = new THREE.Mesh(new THREE.SphereGeometry(0.55, 32, 32), whiteMat);
chest.position.set(0, 1.2, 0.7);
chest.scale.set(1.1, 1, 0.8);
cat.add(chest);

// Head
const head = new THREE.Mesh(new THREE.SphereGeometry(0.7, 32, 32), furMat);
head.position.set(0, 2.35, 0.85);
head.castShadow = true;
cat.add(head);

// Forehead stripes
for (let i = -1; i <= 1; i++) {
  const stripe = new THREE.Mesh(
    new THREE.BoxGeometry(0.06, 0.35, 0.05),
    darkFurMat
  );
  stripe.position.set(i * 0.15, 2.75, 1.48);
  stripe.rotation.x = -0.2;
  cat.add(stripe);
}

// Ears
function makeEar(x) {
  const ear = new THREE.Group();
  const outer = new THREE.Mesh(new THREE.ConeGeometry(0.22, 0.45, 4), furMat);
  outer.castShadow = true;
  const inner = new THREE.Mesh(new THREE.ConeGeometry(0.13, 0.3, 4), innerEarMat);
  inner.position.z = 0.03;
  ear.add(outer, inner);
  ear.position.set(x, 2.95, 0.85);
  ear.rotation.z = x > 0 ? -0.3 : 0.3;
  ear.rotation.x = -0.15;
  return ear;
}
cat.add(makeEar(-0.4), makeEar(0.4));

// Eyes
function makeEye(x) {
  const eyeGroup = new THREE.Group();
  const eyeWhite = new THREE.Mesh(new THREE.SphereGeometry(0.13, 16, 16), whiteMat);
  eyeWhite.scale.set(1.2, 1, 0.7);
  const eye = new THREE.Mesh(new THREE.SphereGeometry(0.1, 16, 16), eyeMat);
  eye.position.z = 0.05;
  const pupil = new THREE.Mesh(new THREE.SphereGeometry(0.055, 16, 16), pupilMat);
  pupil.position.z = 0.1;
  const highlight = new THREE.Mesh(
    new THREE.SphereGeometry(0.025, 8, 8),
    new THREE.MeshBasicMaterial({ color: 0xffffff })
  );
  highlight.position.set(0.03, 0.03, 0.12);
  eyeGroup.add(eyeWhite, eye, pupil, highlight);
  eyeGroup.position.set(x, 2.4, 1.48);
  return eyeGroup;
}
cat.add(makeEye(-0.25), makeEye(0.25));

// Nose
const nose = new THREE.Mesh(new THREE.SphereGeometry(0.06, 16, 16), noseMat);
nose.position.set(0, 2.22, 1.52);
cat.add(nose);

// Mouth (tiny line)
const mouthGeo = new THREE.BufferGeometry().setFromPoints([
  new THREE.Vector3(-0.08, 2.17, 1.53),
  new THREE.Vector3(0, 2.19, 1.55),
  new THREE.Vector3(0.08, 2.17, 1.53),
]);
const mouth = new THREE.Line(mouthGeo, new THREE.LineBasicMaterial({ color: 0x8b4513 }));
cat.add(mouth);

// Whiskers
function makeWhisker(side) {
  const whiskers = new THREE.Group();
  for (let i = -1; i <= 1; i++) {
    const points = [
      new THREE.Vector3(0, i * 0.04, 0),
      new THREE.Vector3(side * 0.6, i * 0.06 + 0.02, 0.05),
    ];
    const geo = new THREE.BufferGeometry().setFromPoints(points);
    const line = new THREE.Line(geo, new THREE.LineBasicMaterial({ color: 0xdddddd }));
    whiskers.add(line);
  }
  whiskers.position.set(side * 0.2, 2.2, 1.5);
  return whiskers;
}
cat.add(makeWhisker(-1), makeWhisker(1));

// Legs
function makeLeg(x, z, scaleY) {
  const leg = new THREE.Mesh(new THREE.CylinderGeometry(0.14, 0.12, 0.8, 12), furMat);
  leg.position.set(x, 0.5, z);
  leg.scale.y = scaleY || 1;
  leg.castShadow = true;
  return leg;
}
cat.add(makeLeg(-0.45, 0.5, 1));
cat.add(makeLeg(0.45, 0.5, 1));
cat.add(makeLeg(-0.45, -0.4, 0.9));
cat.add(makeLeg(0.45, -0.4, 0.9));

// Paws
function makePaw(x, z) {
  const paw = new THREE.Mesh(new THREE.SphereGeometry(0.14, 12, 12), whiteMat);
  paw.position.set(x, 0.12, z);
  paw.scale.y = 0.5;
  return paw;
}
cat.add(makePaw(-0.45, 0.5), makePaw(0.45, 0.5));
cat.add(makePaw(-0.45, -0.4), makePaw(0.45, -0.4));

// Tail
const tailCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 1.0, -1.1),
  new THREE.Vector3(0, 1.5, -1.6),
  new THREE.Vector3(0.1, 2.2, -1.7),
  new THREE.Vector3(0.3, 2.7, -1.5),
  new THREE.Vector3(0.4, 3.0, -1.2),
]);
const tail = new THREE.Mesh(
  new THREE.TubeGeometry(tailCurve, 20, 0.1, 12, false),
  furMat
);
tail.castShadow = true;
cat.add(tail);

scene.add(cat);

// ── Floating particles (dust motes) ──
const particleCount = 60;
const particles = new THREE.Group();
for (let i = 0; i < particleCount; i++) {
  const p = new THREE.Mesh(
    new THREE.SphereGeometry(0.02, 6, 6),
    new THREE.MeshBasicMaterial({ color: 0xffeedd, transparent: true, opacity: 0.4 })
  );
  p.position.set(
    (Math.random() - 0.5) * 12,
    Math.random() * 6,
    (Math.random() - 0.5) * 12
  );
  particles.add(p);
}
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Breathing
  body.scale.y = 0.85 + Math.sin(t * 1.5) * 0.015;
  body.scale.x = 1 + Math.sin(t * 1.5) * 0.01;
  head.position.y = 2.35 + Math.sin(t * 1.5) * 0.02;

  // Ear twitch
  cat.children.forEach(child => {
    if (child.rotation && child.position.y > 2.8) {
      child.rotation.z += Math.sin(t * 3) * 0.001;
    }
  });

  // Tail wag
  tail.rotation.y = Math.sin(t * 2) * 0.15;

  // Subtle head tilt
  head.rotation.z = Math.sin(t * 0.8) * 0.03;

  // Particles float
  particles.children.forEach((p, i) => {
    p.position.y += Math.sin(t + i) * 0.001;
    p.position.x += Math.cos(t * 0.5 + i) * 0.0005;
  });

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's Inside

| Feature | Details |
|---|---|
| **Cat body** | Scaled sphere with chest patch |
| **Head** | Sphere with forehead stripes, ears (cone pairs), eyes (layered spheres with highlights), nose, mouth line, and whiskers |
| **Legs & paws** | Cylinders + flattened spheres |
| **Tail** | `TubeGeometry` along a CatmullRom spline |
| **Lighting** | Warm directional + cool rim + ambient |
| **Shadows** | PCF soft shadow map on the ground plane |
| **Animation** | Breathing scale, head bob, ear twitch, tail wag, floating dust particles |
| **Controls** | `OrbitControls` — drag to rotate, scroll to zoom |

Just save it as `index.html` and open in any modern browser — no build step needed.

Here's a complete, self-contained `index.html` that builds a simple procedural car using Three.js primitives. Just save it and open in a browser (a local server is recommended for ES modules, but it often works directly in modern browsers).

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Car</title>
  <style>
    body { margin: 0; overflow: hidden; background: #111; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script type="module">
    import * as THREE from 'https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js';

    // Scene & Camera
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87CEEB);
    scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

    const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(4, 3, 4);
    camera.lookAt(0, 0, 0);

    // Renderer
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    // Lights
    scene.add(new THREE.AmbientLight(0xffffff, 0.6));
    const sun = new THREE.DirectionalLight(0xffffff, 1.2);
    sun.position.set(5, 10, 5);
    sun.castShadow = true;
    sun.shadow.mapSize.set(1024, 1024);
    scene.add(sun);

    // Ground
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(40, 40),
      new THREE.MeshStandardMaterial({ color: 0x33aa33 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // Car Group
    const car = new THREE.Group();

    // Chassis
    const chassis = new THREE.Mesh(
      new THREE.BoxGeometry(2, 0.4, 1),
      new THREE.MeshStandardMaterial({ color: 0xd63031 })
    );
    chassis.position.y = 0.5;
    chassis.castShadow = true;
    car.add(chassis);

    // Cabin
    const cabin = new THREE.Mesh(
      new THREE.BoxGeometry(1.2, 0.35, 0.85),
      new THREE.MeshStandardMaterial({ color: 0x2d3436, roughness: 0.2 })
    );
    cabin.position.set(-0.1, 0.9, 0);
    cabin.castShadow = true;
    car.add(cabin);

    // Wheels
    const wheelGeo = new THREE.CylinderGeometry(0.25, 0.25, 0.2, 16);
    const wheelMat = new THREE.MeshStandardMaterial({ color: 0x111111 });
    const wheelPos = [
      { x: 0.6, z: 0.55 }, { x: 0.6, z: -0.55 },
      { x: -0.6, z: 0.55 }, { x: -0.6, z: -0.55 }
    ];
    wheelPos.forEach(p => {
      const wheel = new THREE.Mesh(wheelGeo, wheelMat);
      wheel.rotation.x = Math.PI / 2;
      wheel.position.set(p.x, 0.25, p.z);
      wheel.castShadow = true;
      car.add(wheel);
    });

    scene.add(car);

    // Animation Loop
    function animate(time) {
      requestAnimationFrame(animate);
      car.rotation.y = time * 0.0005; // Gentle spin
      renderer.render(scene, camera);
    }
    animate(0);

    // Resize Handler
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

### Features:
- **Procedural Car**: Built from basic geometries (boxes for body/cabin, cylinders for wheels)
- **Lighting & Shadows**: Directional light with soft shadows + ambient fill
- **Responsive**: Automatically adjusts to window size
- **Animated**: Slowly rotates to showcase the model
- **Zero dependencies**: Only pulls Three.js from a reliable CDN

💡 *Tip: For the best experience, serve it via a simple local server (e.g., `npx serve .` or VS Code's Live Server) to avoid CORS restrictions with ES modules.*

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Dog</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
#info {
  position: absolute; top: 12px; left: 50%; transform: translateX(-50%);
  color: #fff; font-family: 'Segoe UI', sans-serif; font-size: 14px;
  background: rgba(0,0,0,0.5); padding: 8px 18px; border-radius: 20px;
  pointer-events: none;
}
</style>
</head>
<body>
<div id="info">🐕 Drag to orbit · Scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.012);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(6, 5, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 4;
controls.maxDistance = 20;

// ── Lighting ─────────────────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambientLight);

const sunLight = new THREE.DirectionalLight(0xfff4e0, 1.8);
sunLight.position.set(8, 15, 10);
sunLight.castShadow = true;
sunLight.shadow.mapSize.set(2048, 2048);
sunLight.shadow.camera.near = 1;
sunLight.shadow.camera.far = 40;
sunLight.shadow.camera.left = -10;
sunLight.shadow.camera.right = 10;
sunLight.shadow.camera.top = 10;
sunLight.shadow.camera.bottom = -10;
sunLight.shadow.bias = -0.001;
scene.add(sunLight);

const fillLight = new THREE.DirectionalLight(0xaaccff, 0.4);
fillLight.position.set(-5, 3, -5);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffaa66, 0.3);
rimLight.position.set(0, 2, -8);
scene.add(rimLight);

// ── Materials ────────────────────────────────────────────────
const furMat = new THREE.MeshStandardMaterial({ color: 0xC4884D, roughness: 0.85, metalness: 0.0 });
const darkFurMat = new THREE.MeshStandardMaterial({ color: 0x8B5E3C, roughness: 0.85, metalness: 0.0 });
const bellyMat = new THREE.MeshStandardMaterial({ color: 0xE8C99B, roughness: 0.8, metalness: 0.0 });
const noseMat = new THREE.MeshStandardMaterial({ color: 0x2a1a0a, roughness: 0.4, metalness: 0.1 });
const eyeWhiteMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.3 });
const eyePupilMat = new THREE.MeshStandardMaterial({ color: 0x1a0a00, roughness: 0.2, metalness: 0.3 });
const tongueMat = new THREE.MeshStandardMaterial({ color: 0xE8707A, roughness: 0.6 });
const collarMat = new THREE.MeshStandardMaterial({ color: 0xCC2222, roughness: 0.5 });
const tagMat = new THREE.MeshStandardMaterial({ color: 0xFFD700, roughness: 0.3, metalness: 0.7 });

// ── Dog Group ────────────────────────────────────────────────
const dog = new THREE.Group();
scene.add(dog);

// Body
const bodyGeo = new THREE.SphereGeometry(1, 32, 32);
bodyGeo.scale(1, 0.75, 1.3);
const body = new THREE.Mesh(bodyGeo, furMat);
body.position.set(0, 1.8, 0);
body.castShadow = true;
dog.add(body);

// Belly
const bellyGeo = new THREE.SphereGeometry(0.75, 32, 32);
bellyGeo.scale(0.9, 0.6, 1.1);
const belly = new THREE.Mesh(bellyGeo, bellyMat);
belly.position.set(0, 1.35, 0);
dog.add(belly);

// Chest (front)
const chestGeo = new THREE.SphereGeometry(0.65, 32, 32);
chestGeo.scale(1, 0.9, 0.7);
const chest = new THREE.Mesh(chestGeo, bellyMat);
chest.position.set(0, 1.7, 1.15);
dog.add(chest);

// ── Head Group (for animation) ──────────────────────────────
const headGroup = new THREE.Group();
headGroup.position.set(0, 2.5, 1.45);
dog.add(headGroup);

// Head
const headGeo = new THREE.SphereGeometry(0.7, 32, 32);
headGeo.scale(1, 0.95, 0.9);
const head = new THREE.Mesh(headGeo, furMat);
head.castShadow = true;
headGroup.add(head);

// Snout
const snoutGeo = new THREE.SphereGeometry(0.35, 32, 32);
snoutGeo.scale(1.1, 0.8, 1.3);
const snout = new THREE.Mesh(snoutGeo, bellyMat);
snout.position.set(0, -0.15, 0.55);
snout.castShadow = true;
headGroup.add(snout);

// Muzzle line (dark)
const muzzleGeo = new THREE.SphereGeometry(0.28, 32, 32);
muzzleGeo.scale(1, 0.7, 1.1);
const muzzle = new THREE.Mesh(muzzleGeo, darkFurMat);
muzzle.position.set(0, -0.1, 0.58);
headGroup.add(muzzle);

// Nose
const noseGeo = new THREE.SphereGeometry(0.12, 16, 16);
noseGeo.scale(1.3, 0.7, 0.9);
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.set(0, -0.05, 0.85);
headGroup.add(nose);

// Mouth line (small dark curve)
const mouthGeo = new THREE.TorusGeometry(0.1, 0.015, 8, 12, Math.PI);
const mouth = new THREE.Mesh(mouthGeo, noseMat);
mouth.position.set(0, -0.18, 0.78);
mouth.rotation.x = Math.PI;
headGroup.add(mouth);

// Tongue
const tongueGeo = new THREE.CapsuleGeometry(0.06, 0.2, 8, 12);
const tongue = new THREE.Mesh(tongueGeo, tongueMat);
tongue.position.set(0, -0.35, 0.7);
tongue.rotation.x = 0.3;
