smokeGeo.setAttribute('size', new THREE.BufferAttribute(smokeSizes, 1));
const smokeMat = new THREE.PointsMaterial({ color: 0xcccccc, size: 0.3, transparent: true, opacity: 0.4, sizeAttenuation: true });
