        0, 0, 0,    2.8, -0.1, 0.1,    2.0, -0.3, 0.2,
        // bottom face
        0, 0, 0,    2.0, -0.3, 0.2,    2.5, 0.8, -0.3,
      ];
      wingGeo.setAttribute('position', new THREE.Float32BufferAttribute(wv, 3));
      wingGeo.computeVertexNormals();

      const leftWingPivot = new THREE.Group();
      leftWingPivot.position.set(-0.9, 0, 0);
      const leftWing = new THREE.Mesh(wingGeo, wingMat);
      leftWing.castShadow = true;
      leftWingPivot.add(leftWing);
      bird.add(leftWingPivot);

      const rightWingPivot = new THREE.Group();
      rightWingPivot.position.set(0.9, 0, 0);
      const rightWingMesh = new THREE.Mesh(wingGeo, wingMat);
      rightWingMesh.castShadow = true;
      rightWingMesh.scale.x = -1; // mirror
      rightWingPivot.add(rightWingMesh);
      bird.add(rightWingPivot);

      // Tail feathers
      const tailGeo = new THREE.BufferGeometry();
      const tv = [
        0,0,0,  0.8,0.3,-1.5,  0.3,0.1,-1.8,
        0,0,0,  0.3,0.1,-1.8, -0.3,0.1,-1.8,
        0,0,0, -0.3,0.1,-1.8, -0.8,0.3,-1.5,
      ];
      tailGeo.setAttribute('position', new THREE.Float32BufferAttribute(tv, 3));
      tailGeo.computeVertexNormals();
      const tail = new THREE.Mesh(tailGeo, tailMat);
