renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

/* ─── scene & camera ─── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a18);
scene.fog = new THREE.FogExp2(0x0a0a18, 0.018);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 3, 10);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.target.set(0, 2.5, 0);
controls.maxPolarAngle = Math.PI * 0.85;
controls.minDistance = 4;
controls.maxDistance = 25;

/* ─── lighting ─── */
scene.add(new THREE.AmbientLight(0x303050, 0.8));

const sun = new THREE.DirectionalLight(0xfff4e0, 2.5);
sun.position.set(5, 10, 6);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
scene.add(sun);

const rim = new THREE.DirectionalLight(0x6080ff, 0.6);
rim.position.set(-4, 6, -5);
scene.add(rim);

const point = new THREE.PointLight(0xff6699, 1.5, 15);
point.position.set(0, 5, 2);
scene.add(point);

/* ─── helpers ─── */
function petalShape(w, h, curve) {
  const s = new THREE.Shape();
  s.moveTo(0, 0);
  s.bezierCurveTo(w * 0.5, h * 0.15, w * 0.6, h * 0.6, 0, h);
  s.bezierCurveTo(-w * 0.6, h * 0.6, -w * 0.5, h * 0.15, 0, 0);
  return s;
}

function leafShape(w, h) {
  const s = new THREE.Shape();
  s.moveTo(0, 0);
  s.bezierCurveTo(w * 0.8, h * 0.1, w * 0.7, h * 0.7, 0, h);
  s.bezierCurveTo(-w * 0.7, h * 0.7, -w * 0.8, h * 0.1, 0, 0);
  return s;
}

function createPetalMesh(width, height, color, segments = 12) {
  const shape = petalShape(width, height, 0.5);
  const geo = new THREE.ShapeGeometry(shape, segments);
  // bend the petal along its local X-axis
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    const t = y / height;
    pos.setZ(i, -Math.abs(x) * 0.6 + t * t * -0.15);
  }
  geo.computeVertexNormals();

  const mat = new THREE.MeshStandardMaterial({
    color,
    side: THREE.DoubleSide,
    roughness: 0.45,
    metalness: 0.05,
    flatShading: false,
  });
  return new THREE.Mesh(geo, mat);
}

function createLeafMesh(w, h, color) {
  const shape = leafShape(w, h);
  const geo = new THREE.ShapeGeometry(shape, 10);
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const y = pos.getY(i);
    const t = y / h;
    pos.setZ(i, t * t * -0.12);
  }
  geo.computeVertexNormals();
  const mat = new THREE.MeshStandardMaterial({
    color,
    side: THREE.DoubleSide,
    roughness: 0.6,
    metalness: 0.0,
  });
  return new THREE.Mesh(geo, mat);
}

/* ─── flower group ─── */
const flower = new THREE.Group();
scene.add(flower);

/* ─── stem ─── */
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 0, 0),
  new THREE.Vector3(0.05, 1.5, 0),
  new THREE.Vector3(0, 3, 0),
  new THREE.Vector3(0, 4.2, 0),
]);
const stemGeo = new THREE.TubeGeometry(stemCurve, 32, 0.07, 8, false);
const stemMat = new THREE.MeshStandardMaterial({ color: 0x2a7a2a, roughness: 0.7 });
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
flower.add(stem);

/* ─── thorns (small bumps on stem) ─── */
for (let i = 0; i < 6; i++) {
  const t = 0.15 + i * 0.12;
  const p = stemCurve.getPointAt(t);
  const angle = (i % 2 === 0) ? 0 : Math.PI;
  const thorn = new THREE.Mesh(
    new THREE.ConeGeometry(0.02, 0.1, 4),
    stemMat
  );
  thorn.position.copy(p);
  thorn.position.x += Math.cos(angle) * 0.07;
  thorn.position.z += Math.sin(angle) * 0.07;
  thorn.rotation.z = Math.PI / 2.5;
  thorn.rotation.y = angle;
  flower.add(thorn);
}

/* ─── leaves ─── */
const leafPositions = [
  { t: 0.2, angle: 0.3,  tilt: -0.6, scale: 1.0 },
  { t: 0.35, angle: Math.PI + 0.2, tilt: 0.5,  scale: 0.9 },
  { t: 0.55, angle: -0.4,  tilt: -0.4, scale: 0.85 },
  { t: 0.7,  angle: Math.PI - 0.3, tilt: 0.3, scale: 0.7 },
];
const leafGroup = new THREE.Group();
flower.add(leafGroup);

leafPositions.forEach(l => {
  const p = stemCurve.getPointAt(l.t);
  const leaf = createLeafMesh(0.35 * l.scale, 1.2 * l.scale, 0x3a9a3a);
  leaf.position.copy(p);
  leaf.rotation.y = l.angle;
  leaf.rotation.x = l.tilt;
  leaf.castShadow = true;
  leafGroup.add(leaf);
});

