    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.target.set(0, 1.5, 0);

    // ── Materials ──
    const baseMat     = new THREE.MeshStandardMaterial({ color: 0x2c2c2c, metalness: 0.9, roughness: 0.2 });
    const poleMat     = new THREE.MeshStandardMaterial({ color: 0x3a3a3a, metalness: 0.85, roughness: 0.15 });
    const shadeMat    = new THREE.MeshStandardMaterial({
      color: 0xfff4e0, metalness: 0.0, roughness: 0.8, side: THREE.DoubleSide
    });
    const shadeInner  = new THREE.MeshStandardMaterial({
      color: 0xffeedd, metalness: 0.0, roughness: 0.9, side: THREE.BackSide, emissive: 0xffaa33, emissiveIntensity: 0.4
    });
    const bulbMat     = new THREE.MeshStandardMaterial({ color: 0xffffee, emissive: 0xffcc44, emissiveIntensity: 2.0 });
    const floorMat    = new THREE.MeshStandardMaterial({ color: 0x16213e, metalness: 0.3, roughness: 0.7 });

    // ── Lamp Group ──
    const lamp = new THREE.Group();

    // Base – bottom disc
    const baseBottom = new THREE.Mesh(new THREE.CylinderGeometry(0.6, 0.65, 0.06, 48), baseMat);
    baseBottom.position.y = 0.03;
    baseBottom.castShadow = true;
    baseBottom.receiveShadow = true;
    lamp.add(baseBottom);

    // Base – top disc
    const baseTop = new THREE.Mesh(new THREE.CylinderGeometry(0.5, 0.55, 0.05, 48), baseMat);
    baseTop.position.y = 0.08;
    baseTop.castShadow = true;
    lamp.add(baseTop);

    // Pole
    const pole = new THREE.Mesh(new THREE.CylinderGeometry(0.035, 0.04, 2.4, 16), poleMat);
    pole.position.y = 1.3;
    pole.castShadow = true;
    lamp.add(pole);

    // Decorative ring on pole
    const ring = new THREE.Mesh(new THREE.TorusGeometry(0.055, 0.015, 8, 24), baseMat);
    ring.position.y = 1.8;
    ring.rotation.x = Math.PI / 2;
    lamp.add(ring);

    // Shade (frustum shape)
    const shadeGeo = new THREE.CylinderGeometry(0.25, 0.7, 0.65, 48, 1, true);
    const shade = new THREE.Mesh(shadeGeo, shadeMat);
    shade.position.y = 2.75;
    shade.castShadow = true;
    lamp.add(shade);

