    const shadeInside = new THREE.Mesh(shadeGeo.clone(), shadeInner);
    shadeInside.position.y = 2.75;
    lamp.add(shadeInside);

    // Shade top cap (small disc)
    const capGeo = new THREE.CircleGeometry(0.25, 48);
    const cap = new THREE.Mesh(capGeo, shadeMat);
    cap.position.y = 3.07;
    cap.rotation.x = -Math.PI / 2;
    lamp.add(cap);

    // Pull chain
    const chainMat = new THREE.MeshStandardMaterial({ color: 0xccbbaa, metalness: 0.7, roughness: 0.3 });
    const chain = new THREE.Mesh(new THREE.CylinderGeometry(0.005, 0.005, 0.5, 8), chainMat);
    chain.position.set(0.35, 2.55, 0);
    lamp.add(chain);

    const chainBall = new THREE.Mesh(new THREE.SphereGeometry(0.02, 12, 12), chainMat);
    chainBall.position.set(0.35, 2.3, 0);
    lamp.add(chainBall);

