    bulb.position.y = 2.5;
    lamp.add(bulb);

    // Bulb socket
    const socket = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.07, 0.12, 16), baseMat);
    socket.position.y = 2.42;
    lamp.add(socket);

    scene.add(lamp);

    // ── Floor ──
    const floor = new THREE.Mesh(new THREE.CircleGeometry(12, 64), floorMat);
    floor.rotation.x = -Math.PI / 2;
    floor.receiveShadow = true;
    scene.add(floor);

    // ── Lights ──
    const ambient = new THREE.AmbientLight(0x334466, 0.5);
    scene.add(ambient);

    // Main lamp point light (warm glow)
    const lampLight = new THREE.PointLight(0xffaa44, 15, 12, 1.5);
    lampLight.position.set(0, 2.6, 0);
    lampLight.castShadow = true;
    lampLight.shadow.mapSize.set(1024, 1024);
    lampLight.shadow.bias = -0.001;
    scene.add(lampLight);

    // Subtle fill light
    const fillLight = new THREE.DirectionalLight(0x4466aa, 0.3);
    fillLight.position.set(-3, 5, 2);
    scene.add(fillLight);

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle light flicker
      lampLight.intensity = 15 + Math.sin(t * 3.2) * 0.3 + Math.sin(t * 7.1) * 0.15;
      bulbMat.emissiveIntensity = 2.0 + Math.sin(t * 3.2) * 0.1;
      shadeInner.emissiveIntensity = 0.4 + Math.sin(t * 3.2) * 0.05;

      // Subtle chain sway
      chain.rotation.z = Math.sin(t * 1.5) * 0.08;
      chainBall.position.x = 0.35 + Math.sin(t * 1.5) * 0.015;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
