<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Bicycle</title>
<style>*{margin:0;padding:0;overflow:hidden}body{background:#111}</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 15, 30);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(6, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.2, 0);
controls.enableDamping = true;

// Lights
const amb = new THREE.AmbientLight(0x404060, 0.8);
scene.add(amb);

const dir = new THREE.DirectionalLight(0xffeedd, 2);
dir.position.set(5, 8, 5);
dir.castShadow = true;
dir.shadow.mapSize.set(2048, 2048);
dir.shadow.camera.near = 1;
dir.shadow.camera.far = 25;
dir.shadow.camera.left = -8;
dir.shadow.camera.right = 8;
dir.shadow.camera.top = 8;
dir.shadow.camera.bottom = -8;
scene.add(dir);

const rim = new THREE.PointLight(0x4488ff, 1, 10);
rim.position.set(-3, 2, -3);
scene.add(rim);

// Ground
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(40, 40),
  new THREE.MeshStandardMaterial({ color: 0x222233, roughness: 0.85, metalness: 0.1 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

const grid = new THREE.GridHelper(40, 40, 0x333355, 0x222244);
grid.position.y = 0.005;
scene.add(grid);

// ---- Materials ----
const frameMat = new THREE.MeshStandardMaterial({ color: 0xcc2222, roughness: 0.3, metalness: 0.7 });
const darkMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.6, metalness: 0.4 });
const tireMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 });
const chromeMat = new THREE.MeshStandardMaterial({ color: 0xcccccc, roughness: 0.15, metalness: 0.95 });
const spokeMat = new THREE.MeshStandardMaterial({ color: 0xaaaaaa, roughness: 0.2, metalness: 0.8 });
const seatMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.8 });
const pedalMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.5, metalness: 0.6 });

// ---- Helpers ----
function tube(from, to, radius, mat) {
  const dir = new THREE.Vector3().subVectors(to, from);
  const len = dir.length();
  const geo = new THREE.CylinderGeometry(radius, radius, len, 12);
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.copy(from).add(to).multiplyScalar(0.5);
  const up = new THREE.Vector3(0, 1, 0);
  const q = new THREE.Quaternion().setFromUnitVectors(up, dir.normalize());
  mesh.quaternion.copy(q);
  mesh.castShadow = true;
  return mesh;
}

function wheel(cx, cz, r, spokes, mat) {
  const g = new THREE.Group();

  // Tire
  const tire = new THREE.Mesh(new THREE.TorusGeometry(r, 0.1, 12, 48), tireMat);
  tire.rotation.y = Math.PI / 2;
  tire.castShadow = true;
  g.add(tire);

  // Rim
  const rimMesh = new THREE.Mesh(new THREE.TorusGeometry(r - 0.02, 0.025, 8, 48), chromeMat);
  rimMesh.rotation.y = Math.PI / 2;
  g.add(rimMesh);

  // Hub
  const hub = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.08, 0.12, 16), chromeMat);
  hub.rotation.z = Math.PI / 2;
  hub.castShadow = true;
  g.add(hub);

  // Spokes
  for (let i = 0; i < spokes; i++) {
    const angle = (i / spokes) * Math.PI * 2;
    const spokeLen = r - 0.1;
    const s = tube(
      new THREE.Vector3(0, Math.cos(angle) * 0.02, 0),
      new THREE.Vector3(0, Math.cos(angle) * spokeLen, Math.sin(angle) * spokeLen),
      0.008, spokeMat
    );
    s.rotation.x = Math.PI / 2;
    g.add(s);
  }

  // Axle
  const axle = new THREE.Mesh(new THREE.CylinderGeometry(0.02, 0.02, 0.2, 8), chromeMat);
  axle.rotation.z = Math.PI / 2;
  g.add(axle);

  g.position.set(cx, r, cz);
  return g;
}

// ---- Bicycle ----
const bike = new THREE.Group();

// Dimensions
const wheelR = 0.85;
const wheelBase = 2.0;
const rearX = -wheelBase / 2;
const frontX = wheelBase / 2;

// Wheels
bike.add(wheel(rearX, 0, wheelR, 24, tireMat));
bike.add(wheel(frontX, 0, wheelR, 24, tireMat));

// Frame - diamond style
const bottomBracket = new THREE.Vector3(0, 0.35, 0);
const seatTubeTop = new THREE.Vector3(-0.15, 1.1, 0);
const headTubeTop = new THREE.Vector3(frontX - 0.3, 1.0, 0);
const headTubeBottom = new THREE.Vector3(frontX - 0.35, 0.6, 0);
const seatStayRear = new THREE.Vector3(rearX, 0.12, 0);
const seatStayFront = new THREE.Vector3(rearX + 0.15, 0.55, 0);
const chainStay = new THREE.Vector3(rearX, 0.12, 0);

// Seat tube
bike.add(tube(bottomBracket, seatTubeTop, 0.025, frameMat));
// Top tube
bike.add(tube(seatTubeTop, headTubeTop, 0.022, frameMat));
// Down tube
bike.add(tube(headTubeBottom, bottomBracket, 0.025, frameMat));
// Head tube
bike.add(tube(headTubeBottom, headTubeTop, 0.028, frameMat));
// Seat stays
bike.add(tube(seatTubeTop, seatStayRear, 0.015, frameMat));
// Chain stays
bike.add(tube(bottomBracket, chainStay, 0.018, frameMat));

// Fork
bike.add(tube(headTubeBottom, new THREE.Vector3(frontX, 0.12, 0), 0.015, darkMat));

// Handlebars
const handlebarCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(frontX - 0.3, 1.0, -0.25),
  new THREE.Vector3(frontX - 0.25, 1.08, -0.35),
  new THREE.Vector3(frontX - 0.15, 1.12, -0.35),
  new THREE.Vector3(frontX - 0.15, 1.12, 0),
  new THREE.Vector3(frontX - 0.15, 1.12, 0.35),
  new THREE.Vector3(frontX - 0.25, 1.08, 0.35),
  new THREE.Vector3(frontX - 0.3, 1.0, 0.25),
]);
const handlebarGeo = new THREE.TubeGeometry(handlebarCurve, 32, 0.015, 8, false);
const handlebar = new THREE.Mesh(handlebarGeo, darkMat);
handlebar.castShadow = true;
bike.add(handlebar);

// Stem
bike.add(tube(new THREE.Vector3(frontX - 0.3, 1.0, 0), headTubeTop, 0.02, chromeMat));

// Seat
const seatBase = new THREE.Mesh(new THREE.BoxGeometry(0.28, 0.04, 0.14), darkMat);
seatBase.position.set(-0.15, 1.14, 0);
seatBase.castShadow = true;
bike.add(seatBase);
const seatTop = new THREE.Mesh(new THREE.BoxGeometry(0.25, 0.03, 0.12), seatMat);
seatTop.position.set(-0.18, 1.17, 0);
bike.add(seatTop);

// Seat post
bike.add(tube(seatTubeTop, new THREE.Vector3(-0.15, 1.12, 0), 0.018, chromeMat));

// Chainring
const chainring = new THREE.Mesh(new THREE.TorusGeometry(0.12, 0.012, 8, 32), chromeMat);
chainring.position.copy(bottomBracket);
chainring.rotation.y = Math.PI / 2;
bike.add(chainring);

// Cranks & pedals
function crank(x, y, z, angle) {
  const g = new THREE.Group();
  const crankArm = tube(new THREE.Vector3(0, 0, 0), new THREE.Vector3(0, -0.22, 0), 0.012, darkMat);
  g.add(crankArm);
  const pedal = new THREE.Mesh(new THREE.BoxGeometry(0.08, 0.02, 0.04), pedalMat);
  pedal.position.y = -0.22;
  pedal.castShadow = true;
  g.add(pedal);
  g.position.set(x, y, z);
  g.rotation.z = angle;
  return g;
}
bike.add(crank(0, 0.35, 0, 0));
bike.add(crank(0, 0.35, 0, Math.PI));

// Chain (simplified)
const chainCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 0.47, 0.015),
  new THREE.Vector3(0.3, 0.45, 0.015),
  new THREE.Vector3(rearX + 0.1, 0.45, 0.015),
  new THREE.Vector3(rearX, wheelR + 0.15, 0.015),
  new THREE.Vector3(rearX, wheelR - 0.15, 0.015),
  new THREE.Vector3(rearX - 0.1, 0.45, 0.015),
  new THREE.Vector3(-0.3, 0.45, 0.015),
  new THREE.Vector3(0, 0.47, 0.015),
], true);
const chainGeo = new THREE.TubeGeometry(chainCurve, 80, 0.006, 4, true);
const chain = new THREE.Mesh(chainGeo, darkMat);
bike.add(chain);

// Rear sprocket
const sprocket = new THREE.Mesh(new THREE.TorusGeometry(0.08, 0.008, 6, 24), chromeMat);
sprocket.position.set(rearX, wheelR, 0);
sprocket.rotation.y = Math.PI / 2;
bike.add(sprocket);

// Front fork crown
bike.add(tube(new THREE.Vector3(frontX - 0.35, 0.6, 0), new THREE.Vector3(frontX, 0.4, 0), 0.012, darkMat));

bike.position.y = 0;
scene.add(bike);

// ---- Animation ----
let time = 0;
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const dt = clock.getDelta();
  time += dt;

  // Rotate wheels
  const wheelSpeed = 2.5;
  bike.children.forEach((child, i) => {
    if (i === 0 || i === 1) { // wheels
      child.children.forEach(c => {
        if (c.geometry && c.geometry.type === 'TorusGeometry') {
          c.rotation.x = time * wheelSpeed;
        }
      });
      // Rotate the whole wheel group around its local Y
      child.rotation.y = time * wheelSpeed;
    }
  });

  // Rotate chainring
  chainring.rotation.z = -time * wheelSpeed;
  sprocket.rotation.z = -time * wheelSpeed;

  // Pedal rotation
  const crankAngle = time * wheelSpeed;
  bike.children.forEach(child => {
    if (child.isGroup) {
      child.rotation.z = crankAngle;
    }
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
