      vec3 bottomColor = vec3(0.82, 0.35, 0.25);   // warm orange-red
      vec3 midColor    = vec3(0.55, 0.45, 0.65);   // purple
      vec3 topColor    = vec3(0.15, 0.12, 0.35);   // deep blue
      vec3 col = mix(bottomColor, midColor, smoothstep(0.0, 0.35, t));
      col = mix(col, topColor, smoothstep(0.35, 0.8, t));
      return col;
    }

    void main() {
      vec3 dir = normalize(vWorldPos);
      vec3 col = skyGradient(dir);

      // Sun glow near horizon
      vec3 sunDir = normalize(vec3(0.6, 0.08, -0.8));
      float sunDot = max(dot(dir, sunDir), 0.0);
      col += vec3(1.0, 0.7, 0.3) * pow(sunDot, 64.0) * 2.0;
      col += vec3(1.0, 0.5, 0.2) * pow(sunDot, 8.0) * 0.4;

      gl_FragColor = vec4(col, 1.0);
    }
  `
});
