      const y = pos.getY(j);
      const z = pos.getZ(j);
      const noise = 1.0 + (Math.random() - 0.5) * 0.25;
      pos.setXYZ(j, x * noise, y * noise, z * noise);
    }
    geo.computeVertexNormals();

    const offsetX = (Math.random() - 0.5) * 8 * scale;
    const offsetY = (Math.random() - 0.5) * 3 * scale;
    const offsetZ = (Math.random() - 0.5) * 5 * scale;

    geo.translate(offsetX, offsetY, offsetZ);
    geometries.push(geo);

    // Slight color variation
    const c = baseColor.clone();
