      0,
      (Math.random() - 0.5) * 0.08
    );
    for (let k = 0; k < pos.count; k++) {
      colors.push(c.r, c.g, c.b);
    }
    geo.dispose && geo.dispose();
  }

  // Use instanced mesh for all puffs
  const puffGeo = new THREE.IcosahedronGeometry(1, 2);
  const puffMat = new THREE.MeshStandardMaterial({
    color: 0xffffff,
    roughness: 0.9,
    metalness: 0.0,
    transparent: true,
    opacity: 0.88,
    depthWrite: false,
  });

  const instancedMesh = new THREE.InstancedMesh(puffGeo, puffMat, puffs);
  instancedMesh.instanceMatrix.setUsage(THREE.StaticDrawUsage);

  const dummy = new THREE.Object3D();
  const color = new THREE.Color();

  for (let i = 0; i < puffs; i++) {
    const radius = (Math.random() * 0.6 + 0.3) * scale;
    dummy.position.set(
      position.x + (Math.random() - 0.5) * 10 * scale,
      position.y + (Math.random() - 0.5) * 3.5 * scale,
      position.z + (Math.random() - 0.5) * 6 * scale
