<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a2a3a);
scene.fog = new THREE.FogExp2(0x0a2a3a, 0.035);

const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0, 0);

// ── Lights ──
scene.add(new THREE.AmbientLight(0x336699, 1.5));
const dir = new THREE.DirectionalLight(0xffeedd, 2.5);
dir.position.set(5, 10, 7);
scene.add(dir);
const rim = new THREE.DirectionalLight(0x4488cc, 1.0);
rim.position.set(-3, 2, -5);
scene.add(rim);

// ── Materials ──
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0xe8943a, roughness: 0.35, metalness: 0.1
});
const bellyMat = new THREE.MeshStandardMaterial({
  color: 0xf5deb3, roughness: 0.4, metalness: 0.05
});
const finMat = new THREE.MeshStandardMaterial({
  color: 0xd4782a, roughness: 0.5, metalness: 0.05, side: THREE.DoubleSide
});
const tailMat = new THREE.MeshStandardMaterial({
  color: 0xc06020, roughness: 0.5, metalness: 0.05, side: THREE.DoubleSide
});
const eyeWhiteMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.2 });
const eyePupilMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.1 });
const eyeHighlightMat = new THREE.MeshStandardMaterial({ color: 0xffffff, emissive: 0xffffff, emissiveIntensity: 0.5 });

// ── Fish Group ──
const fish = new THREE.Group();
scene.add(fish);

// Body – elongated sphere
const bodyGeo = new THREE.SphereGeometry(1, 32, 24);
bodyGeo.scale(1, 0.7, 1.8);
const body = new THREE.Mesh(bodyGeo, bodyMat);
fish.add(body);

// Belly – slightly smaller, shifted down
const bellyGeo = new THREE.SphereGeometry(0.92, 32, 24);
bellyGeo.scale(0.95, 0.45, 1.6);
const belly = new THREE.Mesh(bellyGeo, bellyMat);
belly.position.set(0, -0.25, 0.1);
fish.add(belly);

// Tail pivot (for animation)
const tailPivot = new THREE.Group();
tailPivot.position.set(0, 0, -1.7);
fish.add(tailPivot);

// Tail – custom shape via ShapeGeometry
const tailShape = new THREE.Shape();
tailShape.moveTo(0, 0);
tailShape.quadraticCurveTo(0.3, 0.3, 0.6, 1.0);
tailShape.quadraticCurveTo(0.15, 0.6, 0, 0.5);
tailShape.quadraticCurveTo(-0.15, 0.6, -0.6, 1.0);
tailShape.quadraticCurveTo(-0.3, 0.3, 0, 0);
const tailGeo = new THREE.ShapeGeometry(tailShape, 12);
const tail = new THREE.Mesh(tailGeo, tailMat);
tail.rotation.z = Math.PI; // point backward
tail.position.z = -0.05;
tailPivot.add(tail);

// Dorsal fin
const dorsalShape = new THREE.Shape();
dorsalShape.moveTo(0, 0);
dorsalShape.quadraticCurveTo(0.15, 0.3, 0.05, 0.8);
dorsalShape.quadraticCurveTo(-0.05, 0.5, -0.1, 0.1);
dorsalShape.lineTo(0, 0);
const dorsalGeo = new THREE.ShapeGeometry(dorsalShape, 8);
const dorsal = new THREE.Mesh(dorsalGeo, finMat);
dorsal.position.set(0, 0.65, -0.2);
dorsal.rotation.x = -0.1;
fish.add(dorsal);

// Side fins
function makeSideFin(side) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.1, 0.25, 0.4, 0.55);
  shape.quadraticCurveTo(0.2, 0.3, 0.15, 0.1);
  shape.lineTo(0, 0);
  const geo = new THREE.ShapeGeometry(shape, 8);
  const m = new THREE.Mesh(geo, finMat);
  m.position.set(0, -0.15, 0.4);
  m.rotation.x = 0.8 * side;
  m.rotation.z = -0.5 * side;
  m.scale.x = side;
  return m;
}
fish.add(makeSideFin(1));
fish.add(makeSideFin(-1));

// Eyes
function makeEye(side) {
  const group = new THREE.Group();
  const white = new THREE.Mesh(new THREE.SphereGeometry(0.13, 16, 12), eyeWhiteMat);
  group.add(white);
  const pupil = new THREE.Mesh(new THREE.SphereGeometry(0.08, 12, 10), eyePupilMat);
  pupil.position.set(0.06 * side, 0, 0.08);
  group.add(pupil);
  const highlight = new THREE.Mesh(new THREE.SphereGeometry(0.025, 8, 6), eyeHighlightMat);
  highlight.position.set(0.09 * side, 0.04, 0.11);
  group.add(highlight);
  group.position.set(0.55 * side, 0.2, 0.7);
  return group;
}
fish.add(makeEye(1));
fish.add(makeEye(-1));

// Mouth
const mouthGeo = new THREE.TorusGeometry(0.08, 0.02, 8, 12, Math.PI);
const mouthMat = new THREE.MeshStandardMaterial({ color: 0x8b4513, roughness: 0.6 });
const mouth = new THREE.Mesh(mouthGeo, mouthMat);
mouth.position.set(0, -0.05, 1.75);
mouth.rotation.y = Math.PI / 2;
fish.add(mouth);

// ── Scale pattern (simple dots) ──
const scaleMat = new THREE.MeshStandardMaterial({
  color: 0xc07828, roughness: 0.5, metalness: 0.2
});
for (let i = 0; i < 60; i++) {
  const phi = Math.acos(2 * Math.random() - 1);
  const theta = Math.random() * Math.PI * 2;
  const r = 1.02;
  const x = r * Math.sin(phi) * Math.cos(theta);
  const y = r * Math.cos(phi) * 0.7;
  const z = r * Math.sin(phi) * Math.sin(theta) * 1.8;
  // only place scales on upper/back portion
  if (y < 0.1 && z > 0.5) continue;
  const dot = new THREE.Mesh(new THREE.SphereGeometry(0.03, 6, 4), scaleMat);
  dot.position.set(x, y, z);
  fish.add(dot);
}

// ── Bubbles ──
const bubbles = [];
const bubbleMat = new THREE.MeshStandardMaterial({
  color: 0xaaddff, transparent: true, opacity: 0.35, roughness: 0.05, metalness: 0.1
});
for (let i = 0; i < 30; i++) {
  const s = 0.03 + Math.random() * 0.08;
  const b = new THREE.Mesh(new THREE.SphereGeometry(s, 8, 6), bubbleMat.clone());
  b.position.set(
    (Math.random() - 0.5) * 16,
    (Math.random() - 0.5) * 10,
    (Math.random() - 0.5) * 16
  );
  b.userData.speed = 0.15 + Math.random() * 0.3;
  b.userData.wobble = Math.random() * Math.PI * 2;
  scene.add(b);
  bubbles.push(b);
}

// ── Seaweed ──
const seaweedMat = new THREE.MeshStandardMaterial({ color: 0x2a6e3a, roughness: 0.8, side: THREE.DoubleSide });
for (let i = 0; i < 12; i++) {
  const shape = new THREE.Shape();
  const h = 1.5 + Math.random() * 2;
  const w = 0.15 + Math.random() * 0.15;
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(w * 2, h * 0.4, w, h);
  shape.quadraticCurveTo(-w * 2, h * 0.6, 0, 0);
  const geo = new THREE.ShapeGeometry(shape, 6);
  const s = new THREE.Mesh(geo, seaweedMat);
  s.position.set(
    (Math.random() - 0.5) * 20,
    -3,
    (Math.random() - 0.5) * 20
  );
  s.rotation.y = Math.random() * Math.PI;
  s.userData.phase = Math.random() * Math.PI * 2;
  scene.add(s);
  bubbles.push(b); // reuse for wobble (we'll animate all meshes with phase)
}

// ── Floor ──
const floorGeo = new THREE.PlaneGeometry(40, 40);
const floorMat = new THREE.MeshStandardMaterial({ color: 0x1a3a2a, roughness: 0.95 });
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -4;
scene.add(floor);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Fish swimming path
  fish.position.x = Math.sin(t * 0.4) * 3;
  fish.position.y = Math.sin(t * 0.6) * 0.5;
  fish.position.z = Math.cos(t * 0.3) * 1.5;
  fish.rotation.y = -t * 0.4 + Math.PI * 0.1;
  fish.rotation.z = Math.sin(t * 0.8) * 0.05;

  // Tail wag
  tailPivot.rotation.y = Math.sin(t * 6) * 0.35;

  // Dorsal fin subtle wave
  dorsal.rotation.z = Math.sin(t * 3) * 0.08;

  // Bubbles rise
  bubbles.forEach(b => {
    if (b.geometry.type === 'SphereGeometry') {
      b.position.y += b.userData.speed * 0.02;
      b.position.x += Math.sin(t * 2 + b.userData.wobble) * 0.003;
      if (b.position.y > 8) {
        b.position.y = -6;
        b.position.x = (Math.random() - 0.5) * 16;
        b.position.z = (Math.random() - 0.5) * 16;
      }
    }
  });

  // Seaweed sway
  scene.children.forEach(c => {
    if (c.geometry?.type === 'ShapeGeometry' && c.userData.phase !== undefined) {
      c.rotation.z = Math.sin(t * 1.2 + c.userData.phase) * 0.12;
    }
  });

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
