  <script type="module">
    import * as THREE from "three";
    import { OrbitControls } from "three/addons/controls/OrbitControls.js";

    /* ── scene, camera, renderer ── */
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.Fog(0x1a1a2e, 8, 18);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 5, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.1;
    document.body.appendChild(renderer.domElement);

    /* ── controls ── */
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 0, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.maxPolarAngle = Math.PI / 2.1;
    controls.minDistance = 3;
    controls.maxDistance = 14;

    /* ── lights ── */
    const ambient = new THREE.AmbientLight(0xffeedd, 0.5);
    scene.add(ambient);

    const dir = new THREE.DirectionalLight(0xffffff, 1.8);
    dir.position.set(4, 8, 4);
    dir.castShadow = true;
    dir.shadow.mapSize.set(1024, 1024);
    dir.shadow.camera.near = 1;
    dir.shadow.camera.far = 20;
    dir.shadow.camera.left = -5;
    dir.shadow.camera.right = 5;
    dir.shadow.camera.top = 5;
    dir.shadow.camera.bottom = -5;
    scene.add(dir);

    const rim = new THREE.PointLight(0xff6633, 1.2, 12);
    rim.position.set(-3, 3, -3);
    scene.add(rim);

    /* ── helpers ── */
    function mat(color, roughness = 0.8, metalness = 0.0) {
      return new THREE.MeshStandardMaterial({ color, roughness, metalness });
    }

    function placePepperonis(group, count = 8) {
      const geo = new THREE.CylinderGeometry(0.18, 0.18, 0.04, 16);
      const pepperoniMat = mat(0xcc2200, 0.6);
      for (let i = 0; i < count; i++) {
        const angle = (i / count) * Math.PI * 2 + Math.random() * 0.5;
        const radius = 0.3 + Math.random() * 0.8;
        const p = new THREE.Mesh(geo, pepperoniMat);
        p.position.set(Math.cos(angle) * radius, 0.16, Math.sin(angle) * radius);
        p.rotation.x = Math.PI / 2;
        p.rotation.z = Math.random() * 0.3;
        p.castShadow = true;
        group.add(p);
      }
    }

    function placeCheeseDroplets(group, count = 12) {
      const geo = new THREE.SphereGeometry(0.06, 8, 8);
      const cheeseMat = mat(0xffdd44, 0.5);
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = 0.2 + Math.random() * 0.9;
        const q = new THREE.Mesh(geo, cheeseMat);
        q.position.set(Math.cos(angle) * radius, 0.15 + Math.random() * 0.04, Math.sin(angle) * radius);
        q.scale.set(1, 0.5 + Math.random() * 0.3, 1);
        group.add(q);
      }
    }

    function placeBasil(group, count = 5) {
      const geo = new THREE.SphereGeometry(0.07, 6, 4);
      geo.scale(1, 0.15, 0.7);
      const basilMat = mat(0x338833, 0.7);
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = 0.3 + Math.random() * 0.7;
        const b = new THREE.Mesh(geo, basilMat);
        b.position.set(Math.cos(angle) * radius, 0.17, Math.sin(angle) * radius);
        b.rotation.set(Math.random(), Math.random(), Math.random());
        group.add(b);
      }
    }

    /* ── build pizza ── */
    const pizza = new THREE.Group();

    // Outer crust (torus ring)
    const crustRing = new THREE.Mesh(
      new THREE.TorusGeometry(1.15, 0.18, 12, 32),
      mat(0xd4a030, 0.9)
    );
    crustRing.rotation.x = Math.PI / 2;
    crustRing.position.y = 0.08;
    crustRing.castShadow = true;
    pizza.add(crustRing);

    // Crust top cap (donut top)
    const crustTop = new THREE.Mesh(
      new THREE.RingGeometry(0.97, 1.33, 32),
      mat(0xc8962c, 0.85)
    );
    crustTop.rotation.x = -Math.PI / 2;
    crustTop.position.y = 0.18;
    crustTop.receiveShadow = true;
    pizza.add(crustTop);

    // Crust bottom
    const crustBottom = new THREE.Mesh(
      new THREE.RingGeometry(0.97, 1.33, 32),
      mat(0x8b6914, 0.95)
    );
    crustBottom.rotation.x = Math.PI / 2;
    crustBottom.position.y = 0.02;
    crustBottom.receiveShadow = true;
    pizza.add(crustBottom);

    // Sauce layer
    const sauce = new THREE.Mesh(
      new THREE.CircleGeometry(1.0, 32),
      mat(0xcc3311, 0.75)
    );
    sauce.rotation.x = -Math.PI / 2;
    sauce.position.y = 0.155;
    sauce.receiveShadow = true;
    pizza.add(sauce);

    // Cheese layer (slightly smaller, melted look)
    const cheese = new THREE.Mesh(
      new THREE.CircleGeometry(0.95, 32),
      mat(0xffcc33, 0.55)
    );
    cheese.rotation.x = -Math.PI / 2;
    cheese.position.y = 0.16;
    cheese.receiveShadow = true;
    pizza.add(cheese);

    // Toppings
    placePepperonis(pizza, 9);
    placeCheeseDroplets(pizza, 14);
    placeBasil(pizza, 5);

    // Slight uneven crust bumps
    for (let i = 0; i < 6; i++) {
      const bump = new THREE.Mesh(
        new THREE.SphereGeometry(0.08 + Math.random() * 0.06, 8, 6),
        mat(0xc8962c, 0.85)
      );
      const a = (i / 6) * Math.PI * 2;
      bump.position.set(Math.cos(a) * 1.15, 0.12 + Math.random() * 0.06, Math.sin(a) * 1.15);
      bump.scale.y = 0.6;
      pizza.add(bump);
    }

    // Tilt the pizza slightly for a nice angle
    pizza.rotation.x = -0.15;
    scene.add(pizza);

    /* ── simple ground plane ── */
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(30, 30),
      new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 1 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.5;
    ground.receiveShadow = true;
    scene.add(ground);

    /* ── steam particles ── */
    const steamCount = 30;
    const steamGeo = new THREE.BufferGeometry();
    const steamPositions = new Float32Array(steamCount * 3);
    const steamVelocities = [];
    for (let i = 0; i < steamCount; i++) {
      steamPositions[i * 3] = (Math.random() - 0.5) * 1.2;
      steamPositions[i * 3 + 1] = 0.2 + Math.random() * 1.5;
      steamPositions[i * 3 + 2] = (Math.random() - 0.5) * 1.2;
      steamVelocities.push(0.003 + Math.random() * 0.006);
    }
    steamGeo.setAttribute("position", new THREE.BufferAttribute(steamPositions, 3));
    const steamMat = new THREE.PointsMaterial({
      color: 0xffffff,
      size: 0.08,
      transparent: true,
      opacity: 0.15,
      sizeAttenuation: true,
    });
    const steam = new THREE.Points(steamGeo, steamMat);
    scene.add(steam);

    /* ── animate ── */
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle rotation
      pizza.rotation.y = t * 0.3;

      // Steam rise
      const pos = steam.geometry.attributes.position.array;
      for (let i = 0; i < steamCount; i++) {
        pos[i * 3 + 1] += steamVelocities[i];
        if (pos[i * 3 + 1] > 2.5) {
          pos[i * 3] = (Math.random() - 0.5) * 1.2;
          pos[i * 3 + 1] = 0.2;
          pos[i * 3 + 2] = (Math.random() - 0.5) * 1.2;
        }
      }
      steam.geometry.attributes.position.needsUpdate = true;
      steamMat.opacity = 0.1 + Math.sin(t * 2) * 0.04;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    /* ── resize ── */
    window.addEventListener("resize", () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

## What's in the scene

| Element | Geometry | Details |
|---|---|---|
| **Crust ring** | `TorusGeometry` | Golden-brown outer rim |
| **Crust top/bottom** | `RingGeometry` | Slightly darker underside |
| **Sauce** | `CircleGeometry` | Red tomato layer |
| **Cheese** | `CircleGeometry` | Yellow melted layer + random droplet spheres |
| **Pepperoni** | `CylinderGeometry` ×9 | Scattered with random offsets |
| **Basil** | Squashed `SphereGeometry` ×5 | Green leaf accents |
| **Crust bumps** | `SphereGeometry` ×6 | Irregular puffy spots |
| **Steam** | `Points` ×30 | Rising semi-transparent particles |

**Interactions:** drag to orbit, scroll to zoom, auto-rotates gently. Shadows, fog, ACES tone mapping, and a rim light give it a warm restaurant-vibe look.

