  gold: new THREE.MeshStandardMaterial({ color: 0xddaa33, roughness: 0.2, metalness: 0.9 }),
  smoke: new THREE.MeshStandardMaterial({ color: 0x999999, transparent: true, opacity: 0.4 }),
  carriage: new THREE.MeshStandardMaterial({ color: 0x1a3a6a, roughness: 0.3 }),
  carriageCream: new THREE.MeshStandardMaterial({ color: 0xeeddcc, roughness: 0.3 }),
};

// --- Ground ---
const ground = new THREE.Mesh(new THREE.PlaneGeometry(400, 400), mat.ground);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
