// --- Track ---
function createTrack() {
  const group = new THREE.Group();
  const railGeo = new THREE.BoxGeometry(300, 0.25, 0.2);

  const rail1 = new THREE.Mesh(railGeo, mat.rail);
  rail1.position.set(0, 0.35, -0.7);
  rail1.castShadow = true;
  group.add(rail1);

  const rail2 = new THREE.Mesh(railGeo, mat.rail);
  rail2.position.set(0, 0.35, 0.7);
  rail2.castShadow = true;
