});
const canopy = new THREE.Mesh(canopyGeo, canopyMat);
canopy.castShadow = true;
canopy.receiveShadow = true;
umbrella.add(canopy);

// --- Canopy underside (slightly darker) ---
const underGeo = new THREE.SphereGeometry(2.98, 32, 16, 0, Math.PI * 2, 0, Math.PI * 0.42);
const underMat = new THREE.MeshStandardMaterial({
  color: 0x991133,
  side: THREE.BackSide,
  roughness: 0.7
});
umbrella.add(new THREE.Mesh(underGeo, underMat));

// --- Ribs on canopy surface ---
const ribMat = new THREE.MeshStandardMaterial({ color: 0xD4A843, roughness: 0.4, metalness: 0.3 });
const ribCount = 8;
for (let i = 0; i < ribCount; i++) {
  const angle = (i / ribCount) * Math.PI * 2;
  const ribGeo = new THREE.CylinderGeometry(0.025, 0.025, 3.1, 6);
  const rib = new THREE.Mesh(ribGeo, ribMat);
  rib.position.set(
    Math.sin(angle) * 1.5,
    1.2,
    Math.cos(angle) * 1.5
  );
  rib.rotation.z = Math.cos(angle) * 0.65;
  rib.rotation.x = -Math.sin(angle) * 0.65;
  rib.castShadow = true;
  umbrella.add(rib);
}

// --- Top tip ---
const tipGeo = new THREE.ConeGeometry(0.06, 0.3, 8);
