ground.rotation.x = -Math.PI / 2;
ground.position.y = -5;
ground.receiveShadow = true;
scene.add(ground);

// --- Rain drops (simple falling particles) ---
const rainCount = 300;
const rainGeo = new THREE.BufferGeometry();
const rainPos = new Float32Array(rainCount * 3);
const rainVel = [];
for (let i = 0; i < rainCount; i++) {
  rainPos[i * 3] = (Math.random() - 0.5) * 20;
  rainPos[i * 3 + 1] = Math.random() * 20 - 5;
  rainPos[i * 3 + 2] = (Math.random() - 0.5) * 20;
  rainVel.push(0.05 + Math.random() * 0.1);
}
rainGeo.setAttribute('position', new THREE.BufferAttribute(rainPos, 3));
const rainMat = new THREE.PointsMaterial({ color: 0xAACCEE, size: 0.04, transparent: true, opacity: 0.6 });
const rain = new THREE.Points(rainGeo, rainMat);
scene.add(rain);

// --- Animation ---
umbrella.rotation.y = 0;
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  umbrella.rotation.y = Math.sin(t * 0.3) * 0.15;
  umbrella.position.y = Math.sin(t * 0.8) * 0.15;

  // Rain
  const positions = rainGeo.attributes.position.array;
  for (let i = 0; i < rainCount; i++) {
    positions[i * 3 + 1] -= rainVel[i];
    if (positions[i * 3 + 1] < -5) {
      positions[i * 3 + 1] = 15;
      positions[i * 3] = (Math.random() - 0.5) * 20;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
    }
  }
  rainGeo.attributes.position.needsUpdate = true;

  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
