<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87ceeb);
scene.fog = new THREE.Fog(0x87ceeb, 40, 80);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(8, 5, 10);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.5, 0);
controls.enableDamping = true;
controls.minDistance = 5;
controls.maxDistance = 30;

// ── Lights ──
const ambient = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.5);
sun.position.set(10, 15, 8);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 50;
sun.shadow.camera.left = -15;
sun.shadow.camera.right = 15;
sun.shadow.camera.top = 15;
sun.shadow.camera.bottom = -15;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8ec5fc, 0.4);
fill.position.set(-8, 4, -5);
scene.add(fill);

// ── Materials ──
const bodyMat    = new THREE.MeshStandardMaterial({ color: 0xcc3333, roughness: 0.3, metalness: 0.1 });
const cabMat     = new THREE.MeshStandardMaterial({ color: 0xdddddd, roughness: 0.2, metalness: 0.3 });
const glassMat   = new THREE.MeshStandardMaterial({ color: 0x88ccff, roughness: 0.05, metalness: 0.1, transparent: true, opacity: 0.6 });
const wheelMat   = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.8 });
const rimMat     = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.3, metalness: 0.8 });
const chromeMat  = new THREE.MeshStandardMaterial({ color: 0xcccccc, roughness: 0.05, metalness: 0.95 });
const lightMat   = new THREE.MeshStandardMaterial({ color: 0xffffcc, emissive: 0xffffaa, emissiveIntensity: 0.5 });
const tailMat    = new THREE.MeshStandardMaterial({ color: 0xff3333, emissive: 0xff0000, emissiveIntensity: 0.3 });
const bumperMat  = new THREE.MeshStandardMaterial({ color: 0x444444, roughness: 0.4, metalness: 0.6 });
const chassisMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.6 });
const groundMat  = new THREE.MeshStandardMaterial({ color: 0x556b2f, roughness: 0.9 });

// ── Helpers ──
function box(w, h, d, mat) { return new THREE.Mesh(new THREE.BoxGeometry(w, h, d), mat); }
function cyl(rt, rb, h, seg, mat) { return new THREE.Mesh(new THREE.CylinderGeometry(rt, rb, h, seg), mat); }

// ── Truck Group ──
const truck = new THREE.Group();

// Chassis / frame
const chassis = box(8, 0.2, 2.4, chassisMat);
chassis.position.set(0, 0.6, 0);
chassis.castShadow = true;
truck.add(chassis);

// Cargo box
const cargo = box(5, 3, 2.6, bodyMat);
cargo.position.set(-1.5, 2.2, 0);
cargo.castShadow = true;
cargo.receiveShadow = true;
truck.add(cargo);

// Cargo box roof ridge
const ridge = box(5.1, 0.08, 2.7, chromeMat);
ridge.position.set(-1.5, 3.74, 0);
truck.add(ridge);

// Cargo box tailgate
const tailgate = box(0.1, 2.8, 2.5, bodyMat);
tailgate.position.set(-4.0, 2.1, 0);
tailgate.castShadow = true;
truck.add(tailgate);

// Cargo box tail lights
const tl1 = box(0.05, 0.25, 0.15, tailMat);
tl1.position.set(-4.06, 1.8, 0.8);
truck.add(tl1);
const tl2 = tl1.clone();
tl2.position.z = -0.8;
truck.add(tl2);

// Cab
const cabLower = box(2.8, 1.6, 2.4, cabMat);
cabLower.position.set(2.8, 1.5, 0);
cabLower.castShadow = true;
cabLower.receiveShadow = true;
truck.add(cabLower);

// Cab upper (roof)
const cabUpper = box(2.6, 0.15, 2.2, cabMat);
cabUpper.position.set(2.8, 2.35, 0);
cabUpper.castShadow = true;
truck.add(cabUpper);

// Windshield
const windshield = box(0.05, 1.1, 1.8, glassMat);
windshield.position.set(4.2, 1.9, 0);
windshield.rotation.z = -0.2;
truck.add(windshield);

// Side windows
const sw1 = box(1.2, 0.8, 0.05, glassMat);
sw1.position.set(3.0, 1.85, 1.2);
truck.add(sw1);
const sw2 = sw1.clone();
sw2.position.z = -1.2;
truck.add(sw2);

// Front bumper
const bumper = box(0.3, 0.4, 2.5, chromeMat);
bumper.position.set(4.3, 0.6, 0);
bumper.castShadow = true;
truck.add(bumper);

// Headlights
const hl1 = box(0.1, 0.3, 0.35, lightMat);
hl1.position.set(4.35, 1.0, 0.7);
truck.add(hl1);
const hl2 = hl1.clone();
hl2.position.z = -0.7;
truck.add(hl2);

// Exhaust pipe
const exhaust = cyl(0.06, 0.06, 1.8, 8, chromeMat);
exhaust.position.set(1.5, 1.8, 1.1);
truck.add(exhaust);

// Side mirrors
const mirrorStem = box(0.04, 0.4, 0.04, chromeMat);
mirrorStem.position.set(3.8, 2.0, 1.3);
truck.add(mirrorStem);
const mirrorArm = box(0.04, 0.04, 0.5, chromeMat);
mirrorArm.position.set(3.8, 1.8, 1.55);
truck.add(mirrorArm);
const mirrorPad = box(0.15, 0.25, 0.05, cabMat);
mirrorPad.position.set(3.8, 1.75, 1.85);
truck.add(mirrorPad);

// ── Wheels ──
function makeWheel(x, z) {
  const g = new THREE.Group();

  const tire = cyl(0.55, 0.55, 0.4, 24, wheelMat);
  tire.rotation.x = Math.PI / 2;
  tire.castShadow = true;
  g.add(tire);

  const rim = cyl(0.35, 0.35, 0.42, 16, rimMat);
  rim.rotation.x = Math.PI / 2;
  g.add(rim);

  // Hub cap
  const hub = cyl(0.12, 0.12, 0.44, 12, chromeMat);
  hub.rotation.x = Math.PI / 2;
  g.add(hub);

  // Lug nuts (visual)
  for (let i = 0; i < 5; i++) {
    const a = (i / 5) * Math.PI * 2;
    const nut = cyl(0.03, 0.03, 0.45, 6, chromeMat);
    nut.rotation.x = Math.PI / 2;
    nut.position.set(Math.cos(a) * 0.2, Math.sin(a) * 0.2, 0);
    g.add(nut);
  }

  g.position.set(x, 0.55, z);
  return g;
}

// Rear wheels (dual)
truck.add(makeWheel(-2.8, 1.4));
truck.add(makeWheel(-2.8, -1.4));
truck.add(makeWheel(-2.2, 1.4));
truck.add(makeWheel(-2.2, -1.4));

// Front wheels
truck.add(makeWheel(3.2, 1.4));
truck.add(makeWheel(3.2, -1.4));

// Axles
const axRear = box(1.0, 0.15, 2.8, chassisMat);
axRear.position.set(-2.5, 0.55, 0);
truck.add(axRear);

const axFront = box(0.5, 0.15, 2.8, chassisMat);
axFront.position.set(3.2, 0.55, 0);
truck.add(axFront);

truck.position.y = 0;
scene.add(truck);

// ── Ground ──
const ground = new THREE.Mesh(new THREE.PlaneGeometry(80, 80), groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Road
const road = new THREE.Mesh(
  new THREE.PlaneGeometry(6, 80),
  new THREE.MeshStandardMaterial({ color: 0x444444, roughness: 0.85 })
);
road.rotation.x = -Math.PI / 2;
road.position.y = 0.01;
road.receiveShadow = true;
scene.add(road);

// Road lines
for (let i = -35; i < 35; i += 4) {
  const line = new THREE.Mesh(
    new THREE.PlaneGeometry(0.2, 2),
    new THREE.MeshStandardMaterial({ color: 0xffff00 })
  );
  line.rotation.x = -Math.PI / 2;
  line.position.set(0, 0.02, i);
  scene.add(line);
}

// ── Simple trees ──
function makeTree(x, z) {
  const g = new THREE.Group();
  const trunk = cyl(0.15, 0.2, 1.5, 8, new THREE.MeshStandardMaterial({ color: 0x8B4513 }));
  trunk.position.y = 0.75;
  trunk.castShadow = true;
  g.add(trunk);

  const leaves = new THREE.Mesh(
    new THREE.SphereGeometry(1.2, 8, 6),
    new THREE.MeshStandardMaterial({ color: 0x2d5a1e, roughness: 0.9 })
  );
  leaves.position.y = 2.2;
  leaves.castShadow = true;
  g.add(leaves);

  g.position.set(x, 0, z);
  return g;
}

scene.add(makeTree(-10, 6));
scene.add(makeTree(-7, 9));
scene.add(makeTree(12, 7));
scene.add(makeTree(9, -8));
scene.add(makeTree(-14, -5));
scene.add(makeTree(15, -4));

// ── Animate ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle wheel rotation
  truck.children.forEach(c => {
    if (c.isGroup) {
      c.children.forEach(child => {
        if (child.geometry?.type === 'CylinderGeometry' && child !== truck.children[0]?.children?.[2]) {
          // rotate wheels
        }
      });
    }
  });

  // Subtle headlight pulse
  lightMat.emissiveIntensity = 0.4 + Math.sin(t * 2) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
