// Head — slightly rounded front
const headGeo = new THREE.SphereGeometry(1, 48, 48);
const head = new THREE.Mesh(headGeo, bodyMat);
head.scale.set(1.2, 1.3, 1.2);
head.position.set(3.2, 0.1, 0);
