    const stemMat = new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 0.8 });
    const stem = new THREE.Mesh(stemGeo, stemMat);
    stem.position.set(0, 1.05, 0);
    stem.rotation.z = 0.15;
    apple.add(stem);

    // Leaf
    const leafShape = new THREE.Shape();
    leafShape.moveTo(0, 0);
    leafShape.bezierCurveTo(0.15, 0.15, 0.25, 0.35, 0.12, 0.5);
    leafShape.bezierCurveTo(0.02, 0.42, -0.08, 0.3, 0, 0);
    const leafGeo = new THREE.ShapeGeometry(leafShape, 16);
    const leafMat = new THREE.MeshStandardMaterial({
