sun.shadow.camera.left = -10;
sun.shadow.camera.right = 10;
sun.shadow.camera.top = 10;
sun.shadow.camera.bottom = -10;
scene.add(sun);

const fill = new THREE.DirectionalLight(0xc0d8ff, 0.4);
fill.position.set(-5, 3, -5);
scene.add(fill);

// --- Stripe Texture ---
function createStripeTexture(w = 256, h = 256, stripeW = 12) {
  const c = document.createElement('canvas');
  c.width = w; c.height = h;
  const ctx = c.getContext('2d');
  ctx.fillStyle = '#F5F0E8';
  ctx.fillRect(0, 0, w, h);
  ctx.fillStyle = '#1a1a1a';
  for (let x = 0; x < w; x += stripeW * 2) {
    const variation = Math.random() * 4;
    ctx.fillRect(x, 0, stripeW + variation, h);
  }
  // Add slight noise for realism
  for (let i = 0; i < 800; i++) {
    ctx.fillStyle = Math.random() > 0.5 ? 'rgba(0,0,0,0.08)' : 'rgba(255,255,255,0.06)';
    ctx.fillRect(Math.random() * w, Math.random() * h, 2, 2);
  }
  const tex = new THREE.CanvasTexture(c);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  tex.repeat.set(2, 1);
  return tex;
}

function createDiagonalStripeTexture(w = 256, h = 256) {
  const c = document.createElement('canvas');
  c.width = w; c.height = h;
  const ctx = c.getContext('2d');
  ctx.fillStyle = '#F5F0E8';
  ctx.fillRect(0, 0, w, h);
  ctx.save();
  ctx.strokeStyle = '#1a1a1a';
  for (let i = -h; i < w + h; i += 18) {
    ctx.lineWidth = 6 + Math.random() * 4;
    ctx.beginPath();
    ctx.moveTo(i, 0);
    ctx.lineTo(i + h * 0.4, h);
    ctx.stroke();
  }
  ctx.restore();
  const tex = new THREE.CanvasTexture(c);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  return tex;
}

const stripeTex = createStripeTexture();
const diagTex = createDiagonalStripeTexture();

const bodyMat = new THREE.MeshStandardMaterial({ map: stripeTex, roughness: 0.7, metalness: 0.0 });
const diagMat = new THREE.MeshStandardMaterial({ map: diagTex, roughness: 0.7, metalness: 0.0 });
const darkMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.8 });
const noseMat = new THREE.MeshStandardMaterial({ color: 0x2a2a2a, roughness: 0.5 });
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.3 });
const eyeWhiteMat = new THREE.MeshStandardMaterial({ color: 0xfafafa, roughness: 0.3 });
const hoofMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.6 });
const maneMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 });

// --- Zebra Group ---
const zebra = new THREE.Group();

// Body (main torso)
const bodyGeo = new THREE.BoxGeometry(2.8, 1.6, 1.3, 2, 2, 2);
// Round the body a bit
const bPos = bodyGeo.attributes.position;
for (let i = 0; i < bPos.count; i++) {
  const x = bPos.getX(i), y = bPos.getY(i), z = bPos.getZ(i);
  const len = Math.sqrt(x * x + y * y + z * z);
  const scale = 1.0 - 0.15 * Math.max(0, (len - 1.0) / 2.0);
  bPos.setXYZ(i, x * scale, y * scale, z * scale);
}
bodyGeo.computeVertexNormals();
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.position.set(0, 2.4, 0);
body.castShadow = true;
zebra.add(body);

// Rump (slightly higher, rounded)
const rumpGeo = new THREE.SphereGeometry(0.85, 12, 10);
rumpGeo.scale(1, 1.1, 0.9);
const rump = new THREE.Mesh(rumpGeo, bodyMat);
rump.position.set(-1.0, 2.6, 0);
rump.castShadow = true;
zebra.add(rump);

// Chest / shoulder
const chestGeo = new THREE.SphereGeometry(0.75, 12, 10);
chestGeo.scale(0.9, 1.0, 0.85);
const chest = new THREE.Mesh(chestGeo, bodyMat);
chest.position.set(1.2, 2.5, 0);
chest.castShadow = true;
zebra.add(chest);

// Neck
const neckGeo = new THREE.CylinderGeometry(0.35, 0.5, 2.2, 10);
const neck = new THREE.Mesh(neckGeo, diagMat);
neck.position.set(1.6, 3.8, 0);
neck.rotation.z = -0.35;
neck.castShadow = true;
zebra.add(neck);

// Head
const headGeo = new THREE.BoxGeometry(0.85, 0.55, 0.5, 2, 2, 2);
const hPos = headGeo.attributes.position;
for (let i = 0; i < hPos.count; i++) {
  const x = hPos.getX(i), y = hPos.getY(i), z = hPos.getZ(i);
  const d = Math.sqrt(x * x * 0.5 + y * y + z * z);
  const s = 1.0 - 0.2 * Math.max(0, (d - 0.4) / 0.6);
  hPos.setXYZ(i, x * s, y * s, z * s);
}
headGeo.computeVertexNormals();
const head = new THREE.Mesh(headGeo, diagMat);
head.position.set(2.2, 4.7, 0);
head.castShadow = true;
zebra.add(head);

// Snout
const snoutGeo = new THREE.BoxGeometry(0.5, 0.4, 0.4, 2, 2, 2);
const snout = new THREE.Mesh(snoutGeo, noseMat);
snout.position.set(2.65, 4.55, 0);
snout.castShadow = true;
zebra.add(snout);

// Nostrils
const nostrilGeo = new THREE.SphereGeometry(0.05, 6, 6);
[-0.1, 0.1].forEach(z => {
  const n = new THREE.Mesh(nostrilGeo, darkMat);
  n.position.set(2.88, 4.52, z);
  zebra.add(n);
});

// Eyes
const eyeGeo = new THREE.SphereGeometry(0.09, 8, 8);
const eyeWhiteGeo = new THREE.SphereGeometry(0.1, 8, 8);
[-0.28, 0.28].forEach(z => {
  const white = new THREE.Mesh(eyeWhiteGeo, eyeWhiteMat);
  white.position.set(2.2, 4.85, z);
  zebra.add(white);
  const eye = new THREE.Mesh(eyeGeo, eyeMat);
  eye.position.set(2.26, 4.86, z);
  zebra.add(eye);
  // Eyelash hint
  const lash = new THREE.Mesh(new THREE.BoxGeometry(0.12, 0.02, 0.02), darkMat);
  lash.position.set(2.2, 4.93, z);
  zebra.add(lash);
});

// Ears
const earGeo = new THREE.ConeGeometry(0.1, 0.45, 6);
[-0.2, 0.2].forEach(z => {
  const ear = new THREE.Mesh(earGeo, darkMat);
  ear.position.set(2.0, 5.15, z);
  ear.rotation.z = z > 0 ? 0.2 : -0.2;
  ear.castShadow = true;
  zebra.add(ear);
  // Inner ear
  const inner = new THREE.Mesh(new THREE.ConeGeometry(0.05, 0.3, 6),
    new THREE.MeshStandardMaterial({ color: 0x8B6F6F, roughness: 0.8 }));
  inner.position.set(2.0, 5.15, z);
  inner.rotation.z = z > 0 ? 0.2 : -0.2;
  zebra.add(inner);
});

// Legs
function createLeg(x, z, angle) {
  const leg = new THREE.Group();
  // Upper leg
  const upperGeo = new THREE.CylinderGeometry(0.18, 0.16, 1.4, 8);
  const upper = new THREE.Mesh(upperGeo, diagMat);
  upper.position.y = -0.7;
  upper.castShadow = true;
  leg.add(upper);
  // Lower leg
  const lowerGeo = new THREE.CylinderGeometry(0.14, 0.12, 1.0, 8);
  const lower = new THREE.Mesh(lowerGeo, diagMat);
  lower.position.y = -1.6;
  lower.castShadow = true;
  leg.add(lower);
  // Hoof
  const hoofGeo = new THREE.CylinderGeometry(0.13, 0.11, 0.25, 8);
  const hoof = new THREE.Mesh(hoofGeo, hoofMat);
  hoof.position.y = -2.15;
  hoof.castShadow = true;
  leg.add(hoof);

  leg.position.set(x, 1.6, z);
  leg.rotation.z = angle;
  return leg;
}

const legPositions = [
  { x: 0.9, z: 0.45, a: 0.05 },
  { x: 0.9, z: -0.45, a: -0.05 },
  { x: -0.8, z: 0.45, a: -0.05 },
  { x: -0.8, z: -0.45, a: 0.05 },
];
legPositions.forEach(p => zebra.add(createLeg(p.x, p.z, p.a)));

// Mane
const maneMat2 = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 });
for (let i = 0; i < 12; i++) {
  const t = i / 11;
  const h = 0.25 + Math.random() * 0.15;
  const mGeo = new THREE.BoxGeometry(0.06, h, 0.18);
  const m = new THREE.Mesh(mGeo, maneMat2);
  m.position.set(1.4 + t * 0.8, 3.6 + t * 1.3, 0);
  m.rotation.z = -0.35;
  m.rotation.x = Math.random() * 0.3;
  zebra.add(m);
}

// Tail
const tailGroup = new THREE.Group();
const tailShaft = new THREE.Mesh(new THREE.CylinderGeometry(0.03, 0.02, 1.2, 6), darkMat);
tailShaft.position.y = -0.6;
tailGroup.add(tailShaft);

// Tail tuft
const tuftGeo = new THREE.CylinderGeometry(0.02, 0.12, 0.6, 6);
const tuft = new THREE.Mesh(tuftGeo, maneMat2);
tuft.position.y = -1.2;
tuft.castShadow = true;
tailGroup.add(tuft);

tailGroup.position.set(-1.4, 2.8, 0);
tailGroup.rotation.z = 1.2;
zebra.add(tailGroup);

scene.add(zebra);

// --- Ground ---
const groundGeo = new THREE.PlaneGeometry(60, 60);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x7cb342, roughness: 0.95 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Grass tufts
const grassMat = new THREE.MeshStandardMaterial({ color: 0x5a9e2b, roughness: 1.0 });
for (let i = 0; i < 200; i++) {
  const gGeo = new THREE.ConeGeometry(0.05 + Math.random() * 0.05, 0.3 + Math.random() * 0.3, 4);
  const g = new THREE.Mesh(gGeo, grassMat);
  g.position.set((Math.random() - 0.5) * 30, 0.1, (Math.random() - 0.5) * 30);
  g.rotation.y = Math.random() * Math.PI;
  scene.add(g);
}

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>🍌 Banana</title>
<style>
* { margin: 0; padding: 0; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 8, 20);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0.2, 0);

// --- Banana curve (C-shape spine) ---
const curve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-1.4, -0.3, 0),
  new THREE.Vector3(-1.2,  0.3, 0),
  new THREE.Vector3(-0.6,  0.9, 0),
  new THREE.Vector3( 0.2,  1.2, 0),
  new THREE.Vector3( 0.8,  1.0, 0),
  new THREE.Vector3( 1.3,  0.5, 0),
  new THREE.Vector3( 1.5, -0.1, 0),
], false, 'catmullrom', 0.5);

// --- Tube geometry ---
const tubeGeo = new THREE.TubeGeometry(curve, 128, 0.28, 16, false);

// --- Taper the tube to banana shape ---
const pos = tubeGeo.attributes.position;
const tempVec = new THREE.Vector3();

for (let i = 0; i < pos.count; i++) {
  tempVec.fromBufferAttribute(pos, i);

  // Find approximate distance along curve
  const t = curve.getUtoTmapping(0, tempVec.x);
  const closest = curve.getPointAt(t);

  // Direction from spine to vertex
  const dir = tempVec.clone().sub(closest);
  const dist = dir.length();

  // Taper function: narrow at both ends, bulge in middle
  const taper = Math.sin(t * Math.PI) * 0.7 + 0.3;
  // Extra narrowing at tips
  const tipFactor = 1.0 - Math.pow(Math.abs(t - 0.5) * 2, 4) * 0.5;

  const scale = taper * tipFactor;

  // Flatten slightly (bananas are slightly flattened)
  dir.normalize().multiplyScalar(dist * scale);
  dir.y *= 0.85; // flatten

  // Add slight twist along the curve
  const angle = t * Math.PI * 0.5;
  const cosA = Math.cos(angle * 0.3);
  const sinA = Math.sin(angle * 0.3);
  const flatZ = dir.z * cosA;
  const flatX = dir.z * sinA;

  pos.setXYZ(i, closest.x + dir.x + flatX * 0.3, closest.y + dir.y, closest.z + flatZ);
}

tubeGeo.computeVertexNormals();

// --- Color texture via canvas ---
const canvas = document.createElement('canvas');
canvas.width = 512;
canvas.height = 256;
const ctx = canvas.getContext('2d');

// Yellow gradient
const grad = ctx.createLinearGradient(0, 0, 512, 0);
grad.addColorStop(0,    '#5a8a2a');  // green tip
grad.addColorStop(0.08, '#b8c830');
grad.addColorStop(0.2,  '#e8d44d');
grad.addColorStop(0.5,  '#f5e642');
grad.addColorStop(0.8,  '#f0db35');
grad.addColorStop(0.92, '#d4b830');
grad.addColorStop(1,    '#6b4a1a');  // brown tip
ctx.fillStyle = grad;
ctx.fillRect(0, 0, 512, 256);

// Brown spots
for (let i = 0; i < 60; i++) {
  const x = Math.random() * 512;
  const y = Math.random() * 256;
  const r = Math.random() * 6 + 2;
  ctx.beginPath();
  ctx.arc(x, y, r, 0, Math.PI * 2);
  ctx.fillStyle = `rgba(${100 + Math.random()*40}, ${70 + Math.random()*30}, ${20}, ${0.15 + Math.random()*0.25})`;
  ctx.fill();
}

// Wrinkle lines
for (let i = 0; i < 12; i++) {
  const x = 50 + Math.random() * 400;
  ctx.beginPath();
  ctx.moveTo(x, 0);
  ctx.lineTo(x + (Math.random() - 0.5) * 20, 256);
  ctx.strokeStyle = 'rgba(160, 130, 50, 0.12)';
  ctx.lineWidth = Math.random() * 3 + 1;
  ctx.stroke();
}

const texture = new THREE.CanvasTexture(canvas);
texture.wrapS = THREE.RepeatWrapping;

// --- Banana material ---
const bananaMat = new THREE.MeshStandardMaterial({
  map: texture,
  roughness: 0.45,
  metalness: 0.05,
  bumpMap: texture,
  bumpScale: 0.01,
});

const banana = new THREE.Mesh(tubeGeo, bananaMat);
banana.castShadow = true;
banana.receiveShadow = true;
scene.add(banana);

// --- Stem ---
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-1.4, -0.3, 0),
  new THREE.Vector3(-1.55, -0.55, 0),
  new THREE.Vector3(-1.7, -0.7, 0.05),
]);
const stemGeo = new THREE.TubeGeometry(stemCurve, 16, 0.04, 8, false);
const stemMat = new THREE.MeshStandardMaterial({ color: 0x4a7a20, roughness: 0.7 });
const stem = new THREE.Mesh(stemGeo, stemMat);
banana.add(stem);

// --- Lighting ---
const ambient = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xfff4e0, 2.5);
key.position.set(4, 6, 4);
key.castShadow = true;
scene.add(key);

const fill = new THREE.DirectionalLight(0xc8d8ff, 0.8);
fill.position.set(-4, 2, -2);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xffe0a0, 1.2);
rim.position.set(0, -2, -4);
scene.add(rim);

// --- Ground plane ---
const groundGeo = new THREE.CircleGeometry(5, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.2;
ground.receiveShadow = true;
scene.add(ground);

// --- Gentle float animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  banana.position.y = Math.sin(t * 0.8) * 0.12;
  banana.rotation.z = Math.sin(t * 0.5) * 0.03;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- 🍌 A **curved, tapered banana** built from a `TubeGeometry` along a CatmullRom spline, with custom vertex tapering for realistic shape (pointed ends, bulging middle, slight flattening)
- 🎨 A **procedural canvas texture** with a yellow gradient, green/brown tips, brown age spots, and subtle wrinkle lines
- 🌿 A small **stem** attached at the base
- 💡 **Three-point lighting** (key, fill, rim) with ACES filmic tone mapping
- 🎥 **Orbit controls** — drag to rotate, scroll to zoom
- ✨ A gentle **floating animation**
- 📐 Responsive to window resizing

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Window</title>
  <style>
    * { margin: 0; padding: 0; }
    body { overflow: hidden; background: #000; }
  </style>
</head>
<body>
  <script type="importmap">
    {
      "imports": {
        "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js"
      }
    }
  </script>
  <script type="module">
    import * as THREE from 'three';

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.shadowMap.enabled = true;
    document.body.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87ceeb);

    const camera = new THREE.PerspectiveCamera(50, window.innerWidth / window.innerHeight, 0.1, 100);
    camera.position.set(0, 1.5, 4);
    camera.lookAt(0, 1.5, 0);

    // ── Lighting ──
    scene.add(new THREE.AmbientLight(0xffffff, 0.6));
    const sun = new THREE.DirectionalLight(0xffeedd, 2);
    sun.position.set(3, 5, 4);
    sun.castShadow = true;
    scene.add(sun);

    // ── Wall ──
    const wallGeo = new THREE.BoxGeometry(6, 4, 0.3);
    const wallMat = new THREE.MeshStandardMaterial({ color: 0xf5f0e8 });
    const wall = new THREE.Mesh(wallGeo, wallMat);
    wall.position.set(0, 2, -0.5);
    wall.castShadow = true;
    wall.receiveShadow = true;
    scene.add(wall);

    // ── Window frame ──
    const frameMat = new THREE.MeshStandardMaterial({ color: 0x2a2a2a });
    const W = 1.8, H = 2.0, T = 0.12, D = 0.35; // width, height, thickness, depth

    function bar(w, h) {
      const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, D), frameMat);
      m.castShadow = true;
      return m;
    }

    const framePieces = [
      { s: [W + T * 2, T, D], p: [0, H / 2 + T / 2] },  // top
      { s: [W + T * 2, T, D], p: [0, -H / 2 - T / 2] }, // bottom
      { s: [T, H, D], p: [-W / 2 - T / 2, 0] },          // left
      { s: [T, H, D], p: [W / 2 + T / 2, 0] },           // right
      { s: [T, H, D], p: [0, 0] },                        // center vertical
      { s: [W, T, D], p: [0, 0] },                        // center horizontal
    ];

    framePieces.forEach(({ s, p }) => {
      const m = bar(s[0], s[1]);
      m.position.set(p[0], p[1] + 1.5, -0.3);
      scene.add(m);
    });

    // ── Glass panes ──
    const glassMat = new THREE.MeshPhysicalMaterial({
      color: 0xaaddff,
      transparent: true,
      opacity: 0.25,
      roughness: 0.05,
      metalness: 0.1,
      transmission: 0.8,
      thickness: 0.02,
    });

    const paneW = W / 2 - T, paneH = H / 2 - T;
    [[-paneW / 2 - T / 2, paneH / 2 + T / 2],
     [ paneW / 2 + T / 2, paneH / 2 + T / 2],
     [-paneW / 2 - T / 2,-paneH / 2 - T / 2],
     [ paneW / 2 + T / 2,-paneH / 2 - T / 2]].forEach(([x, y]) => {
      const pane = new THREE.Mesh(new THREE.BoxGeometry(paneW, paneH, 0.02), glassMat);
      pane.position.set(x, y + 1.5, -0.3);
      scene.add(pane);
    });

    // ── Floor ──
    const floor = new THREE.Mesh(
      new THREE.PlaneGeometry(20, 20),
      new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.9 })
    );
    floor.rotation.x = -Math.PI / 2;
    floor.receiveShadow = true;
    scene.add(floor);

    // ── Render loop ──
    function animate() {
      requestAnimationFrame(animate);
      renderer.render(scene, camera);
    }
    animate();

    window.addEventListener('resize', () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    });
  </script>
</body>
</html>
```

**What you get:**

- **Wall** — a warm off-white rectangular wall
- **Window frame** — dark 6-pane grid (3×2) with a center mullion and transom
- **Glass panes** — semi-transparent, slightly blue-tinted `MeshPhysicalMaterial` with transmission
- **Floor** — a simple gray ground plane receiving shadows
- **Lighting** — ambient fill + a warm directional "sun" with shadow casting
- **Sky** — light blue background

Open the file in any modern browser. The scene is static (no orbit controls) to keep it truly minimal — just a clean window on a wall.

