  new THREE.Vector2(0.38, 0.60),
  new THREE.Vector2(0.26, 0.70),
  new THREE.Vector2(0.18, 0.78),
  new THREE.Vector2(0.12, 0.83),
  new THREE.Vector2(0.08, 0.86),
  // handle stem
  new THREE.Vector2(0.04, 0.90),
  new THREE.Vector2(0.02, 0.94),
  new THREE.Vector2(0.00, 0.96),
  // handle loop
  new THREE.Vector2(0.06, 1.00),
  new THREE.Vector2(0.14, 1.04),
  new THREE.Vector2(0.18, 1.10),
