  new THREE.Vector2(0.10, 1.20),
  new THREE.Vector2(0.04, 1.20),
  new THREE.Vector2(0.00, 1.18),
  // back down to crown
  new THREE.Vector2(0.00, 0.86),
];

const bellGeo = new THREE.LatheGeometry(bellProfile, 64);
const bellMat = new THREE.MeshStandardMaterial({
  color: 0xd4a04a,
  metalness: 0.85,
  roughness: 0.25,
  side: THREE.DoubleSide,
});
const bell = new THREE.Mesh(bellGeo, bellMat);
