const winMat = new THREE.MeshStandardMaterial({ color: 0x88ccff, roughness: 0.1, metalness: 0.3, transparent: true, opacity: 0.7 });
for (let i = -1; i <= 1; i += 2) {
  const win = new THREE.Mesh(winGeo, winMat);
