}

/* Mast */
const mastGeo = new THREE.CylinderGeometry(0.08, 0.12, 7, 12);
const mastMat = new THREE.MeshStandardMaterial({ color: 0x3a3a3a, roughness: 0.4, metalness: 0.2 });
const mast = new THREE.Mesh(mastGeo, mastMat);
mast.position.set(1.0, 4.8, 0);
mast.castShadow = true;
boat.add(mast);

/* Main Sail */
const sailShape = new THREE.Shape();
sailShape.moveTo(0, 3.2);
sailShape.quadraticCurveTo(1.8, 2.0, 1.2, -1.0);
sailShape.lineTo(0, -1.0);
sailShape.lineTo(0, 3.2);

const sailGeo = new THREE.ShapeGeometry(sailShape, 16);
const sailMat = new THREE.MeshStandardMaterial({
  color: 0xFAFAFA, roughness: 0.8, side: THREE.DoubleSide,
  transparent: true, opacity: 0.92
});
const sail = new THREE.Mesh(sailGeo, sailMat);

