  flame.scale.set(0.7 * s, 1.8 * s * (0.9 + Math.sin(t * 17) * 0.1), 0.7 * s);
  innerFlame.scale.set(0.8 * s, 1.2 * s, 0.8 * s);

  flameLight.intensity = 15 * s;
  glowSprite.scale.setScalar(2.5 * s);
  flameMat.emissiveIntensity = 3 * s;

  // Subtle sway
  flame.position.x = Math.sin(t * 5) * 0.01;
  innerFlame.position.x = Math.sin(t * 5) * 0.008;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// — Resize —
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

