<script type="module">
import * as THREE from 'three';

const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, .1, 100);
camera.position.set(0, 0, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
document.body.appendChild(renderer.domElement);

// Clock face
const face = new THREE.Mesh(
  new THREE.CylinderGeometry(1, 1, .08, 64),
  new THREE.MeshStandardMaterial({ color: 0x222222, metalness: .6, roughness: .3 })
);
face.rotation.x = Math.PI / 2;
scene.add(face);

// Rim
const rim = new THREE.Mesh(
  new THREE.TorusGeometry(1, .04, 16, 64),
  new THREE.MeshStandardMaterial({ color: 0xcc8844, metalness: .9, roughness: .2 })
);
scene.add(rim);

// Hour markers
for (let i = 0; i < 12; i++) {
  const a = (i / 12) * Math.PI * 2;
  const m = new THREE.Mesh(
    new THREE.BoxGeometry(i % 3 === 0 ? .06 : .03, .12, .06),
    new THREE.MeshStandardMaterial({ color: 0xddddaa, emissive: 0x333322 })
  );
  m.position.set(Math.sin(a) * .88, Math.cos(a) * .88, 0);
  m.rotation.z = -a;
  scene.add(m);
}

// Hands
function makeHand(h, w, len, color) {
  const g = new THREE.BoxGeometry(h, w, len);
  g.translate(0, 0, -len / 2);
  return new THREE.Mesh(g, new THREE.MeshStandardMaterial({ color, metalness: .7, roughness: .3 }));
}

const hourHand   = makeHand(.1, .04, .55, 0xffffff);
const minuteHand = makeHand(.07, .04, .8, 0xffffff);
const secondHand = makeHand(.03, .02, .9, 0xff3333);

scene.add(hourHand, minuteHand, secondHand);

// Center cap
scene.add(new THREE.Mesh(
  new THREE.CylinderGeometry(.06, .06, .12, 16),
  new THREE.MeshStandardMaterial({ color: 0xcc8844, metalness: .9, roughness: .2 })
));

// Lights
scene.add(new THREE.AmbientLight(0x404040, 2));
const dir = new THREE.DirectionalLight(0xffffff, 2);
dir.position.set(2, 3, 4);
scene.add(dir);

// Animate
function tick() {
  requestAnimationFrame(tick);
  const t = new Date();
  const s = t.getSeconds() + t.getMilliseconds() / 1000;
  const m = t.getMinutes() + s / 60;
  const h = (t.getHours() % 12) + m / 60;

  secondHand.rotation.z = -(s / 60) * Math.PI * 2;
  minuteHand.rotation.z = -(m / 60) * Math.PI * 2;
  hourHand.rotation.z   = -(h / 12) * Math.PI * 2;

  renderer.render(scene, camera);
}
tick();

addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
