box(wallT, wallH, wallL, stoneMat, wallL / 2, 1.5 + wallH / 2, 0);

/* ── Crenellations ── */
function addCrenellations(parent, length, axis, offsetZ) {
  const gap = 2.5, w = 1.8, h = 2.5, d = 1.8;
  const count = Math.floor(length / gap);
  for (let i = 0; i < count; i++) {
    const pos = -length / 2 + gap / 2 + i * gap;
    if (axis === 'x') {
      box(w, h, d, darkStoneMat, pos, 1.5 + wallH + h / 2, offsetZ);
    } else {
      box(d, h, w, darkStoneMat, offsetZ, 1.5 + wallH + h / 2, pos);
    }
  }
}
