    );
    saucer.position.y = -0.04;
    saucer.receiveShadow = true;
    saucer.castShadow = true;
    scene.add(saucer);

    // Saucer rim
    const saucerRim = new THREE.Mesh(
      new THREE.TorusGeometry(1.25, 0.03, 12, 48),
