    );
    saucerRim.rotation.x = Math.PI / 2;
    saucerRim.position.y = 0.0;
    scene.add(saucerRim);

    // Saucer inner depression
    const saucerInner = new THREE.Mesh(
      new THREE.CylinderGeometry(0.6, 0.6, 0.02, 48),
      new THREE.MeshStandardMaterial({ color: 0xe8e0d8, roughness: 0.4 })
    );
    saucerInner.position.y = 0.01;
    saucerInner.receiveShadow = true;
    scene.add(saucerInner);

    // ── Table / Ground ───────────────────────────────────────
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(30, 30),
      new THREE.MeshStandardMaterial({ color: 0x2a1f1a, roughness: 0.85 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.08;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Steam Particles ──────────────────────────────────────
    const steamCount = 30;
    const steamGeo = new THREE.BufferGeometry();
    const steamPositions = new Float32Array(steamCount * 3);
    const steamSpeeds = new Float32Array(steamCount);
    const steamOffsets = new Float32Array(steamCount);
    const steamOpacities = new Float32Array(steamCount);

    for (let i = 0; i < steamCount; i++) {
      steamPositions[i * 3] = (Math.random() - 0.5) * 0.6;
      steamPositions[i * 3 + 1] = 1.4 + Math.random() * 2;
      steamPositions[i * 3 + 2] = (Math.random() - 0.5) * 0.6;
      steamSpeeds[i] = 0.3 + Math.random() * 0.5;
      steamOffsets[i] = Math.random() * Math.PI * 2;
      steamOpacities[i] = Math.random();
    }

    steamGeo.setAttribute('position', new THREE.BufferAttribute(steamPositions, 3));

    const steamMat = new THREE.PointsMaterial({
      color: 0xffffff,
      size: 0.15,
      transparent: true,
      opacity: 0.12,
      sizeAttenuation: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
    });

    const steam = new THREE.Points(steamGeo, steamMat);
    scene.add(steam);

    // ── Spoon (optional nice touch) ──────────────────────────
    const spoonGroup = new THREE.Group();

    const spoonBowl = new THREE.Mesh(
      new THREE.SphereGeometry(0.15, 24, 16, 0, Math.PI * 2, 0, Math.PI / 2),
      new THREE.MeshStandardMaterial({ color: 0xcccccc, roughness: 0.15, metalness: 0.85 })
    );
    spoonBowl.rotation.x = -Math.PI / 2;
    spoonGroup.add(spoonBowl);

    const spoonHandle = new THREE.Mesh(
      new THREE.CylinderGeometry(0.025, 0.02, 0.8, 12),
      new THREE.MeshStandardMaterial({ color: 0xcccccc, roughness: 0.15, metalness: 0.85 })
    );
    spoonHandle.position.y = -0.4;
    spoonGroup.add(spoonHandle);

    spoonGroup.position.set(-1.6, 0.15, 0.3);
    spoonGroup.rotation.z = 0.3;
    spoonGroup.rotation.x = -0.1;
    spoonGroup.castShadow = true;
    scene.add(spoonGroup);

    // ── Animation ────────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Steam animation
      const pos = steam.geometry.attributes.position;
      for (let i = 0; i < steamCount; i++) {
        let y = pos.getY(i) + steamSpeeds[i] * 0.016;
        if (y > 3.8) y = 1.4;
        pos.setY(i, y);
        pos.setX(i, Math.sin(t * steamSpeeds[i] + steamOffsets[i]) * 0.25 + (Math.random() - 0.5) * 0.01);
      }
      pos.needsUpdate = true;
      steamMat.opacity = 0.08 + Math.sin(t * 1.5) * 0.03;

      // Gentle cup rotation
      cupGroup.rotation.y = Math.sin(t * 0.3) * 0.05;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
