```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Diamond</title>
  <style>
    * { margin: 0; padding: 0; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // --- Scene ---
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0a0a1a);
    scene.fog = new THREE.FogExp2(0x0a0a1a, 0.08);

    // --- Camera ---
    const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(3, 2, 4);

    // --- Renderer ---
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // --- Controls ---
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.target.set(0, 0, 0);

    // --- Diamond Geometry (Lathe) ---
    const profile = [
      new THREE.Vector2(0.00,  1.15),   // table center (top)
      new THREE.Vector2(0.30,  1.15),   // table edge
      new THREE.Vector2(0.52,  0.78),   // crown / upper girdle
      new THREE.Vector2(0.58,  0.55),   // girdle (widest)
      new THREE.Vector2(0.58,  0.48),   // girdle lower
      new THREE.Vector2(0.00, -1.20),   // culet (bottom point)
    ];
    const diamondGeo = new THREE.LatheGeometry(profile, 32);

    // --- Diamond Material ---
    const diamondMat = new THREE.MeshPhysicalMaterial({
      color: 0xffffff,
      metalness: 0.0,
      roughness: 0.0,
      transmission: 0.97,
      thickness: 2.0,
      ior: 2.42,
      clearcoat: 1.0,
      clearcoatRoughness: 0.0,
      envMapIntensity: 3.0,
      specularIntensity: 1.0,
      specularColor: new THREE.Color(0xffffff),
      attenuationColor: new THREE.Color(0.9, 0.95, 1.0),
      attenuationDistance: 4,
    });

    const diamond = new THREE.Mesh(diamondGeo, diamondMat);
    scene.add(diamond);

    // --- Wireframe edge highlight ---
    const edgeMat = new THREE.MeshBasicMaterial({
      color: 0x88aaff,
      wireframe: true,
      transparent: true,
      opacity: 0.03,
    });
    const edgeMesh = new THREE.Mesh(diamondGeo, edgeMat);
    diamond.add(edgeMesh);

    // --- Environment (simple procedural) ---
    const pmrem = new THREE.PMREMGenerator(renderer);
    pmrem.compileEquirectangularShader();

    const envScene = new THREE.Scene();
    const envGeo = new THREE.SphereGeometry(1, 32, 32);

    // Gradient sky
    const envMat = new THREE.ShaderMaterial({
      side: THREE.BackSide,
      uniforms: {},
      vertexShader: `
        varying vec3 vWorldPos;
        void main() {
          vWorldPos = position;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        varying vec3 vWorldPos;
        void main() {
          float y = normalize(vWorldPos).y;
          vec3 top = vec3(0.05, 0.05, 0.2);
          vec3 mid = vec3(0.15, 0.1, 0.3);
          vec3 bot = vec3(0.02, 0.02, 0.08);
          vec3 col = mix(bot, mid, smoothstep(-0.3, 0.0, y));
          col = mix(col, top, smoothstep(0.0, 0.8, y));
          // bright spots for reflections
          float spot1 = pow(max(dot(normalize(vWorldPos), normalize(vec3(1.0, 0.5, 0.8))), 0.0), 64.0);
          float spot2 = pow(max(dot(normalize(vWorldPos), normalize(vec3(-0.8, 0.3, -0.5))), 0.0), 32.0);
          float spot3 = pow(max(dot(normalize(vWorldPos), normalize(vec3(0.0, 1.0, 0.0))), 0.0), 128.0);
          col += vec3(1.0, 0.95, 0.9) * spot1 * 3.0;
          col += vec3(0.6, 0.8, 1.0) * spot2 * 2.0;
          col += vec3(1.0, 1.0, 1.0) * spot3 * 5.0;
          gl_FragColor = vec4(col, 1.0);
        }
      `,
    });
    const envMesh = new THREE.Mesh(envGeo, envMat);
    envScene.add(envMesh);

    const envMap = pmrem.fromScene(envScene, 0.04).texture;
    scene.environment = envMap;
    pmrem.dispose();

    // --- Lighting ---
    scene.add(new THREE.AmbientLight(0x222244, 0.5));

    const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
    keyLight.position.set(5, 8, 5);
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0x8888ff, 1.5);
    fillLight.position.set(-5, 3, -3);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xffffff, 4, 15);
    rimLight.position.set(-2, 4, -4);
    scene.add(rimLight);

    const bottomLight = new THREE.PointLight(0x4466ff, 2, 10);
    bottomLight.position.set(0, -3, 2);
    scene.add(bottomLight);

    // --- Sparkle particles ---
    const sparkleCount = 60;
    const sparkleGeo = new THREE.BufferGeometry();
    const sparklePos = new Float32Array(sparkleCount * 3);
    const sparkleVel = [];
    for (let i = 0; i < sparkleCount; i++) {
      const theta = Math.random() * Math.PI * 2;
      const r = 1.5 + Math.random() * 3;
      const y = (Math.random() - 0.5) * 5;
      sparklePos[i * 3] = Math.cos(theta) * r;
      sparklePos[i * 3 + 1] = y;
      sparklePos[i * 3 + 2] = Math.sin(theta) * r;
      sparkleVel.push({ theta, r, y, speed: 0.1 + Math.random() * 0.3, phase: Math.random() * Math.PI * 2 });
    }
    sparkleGeo.setAttribute('position', new THREE.BufferAttribute(sparklePos, 3));

    const sparkleMat = new THREE.PointsMaterial({
      color: 0xaaccff,
      size: 0.04,
      transparent: true,
      opacity: 0.6,
      sizeAttenuation: true,
    });
    const sparkles = new THREE.Points(sparkleGeo, sparkleMat);
    scene.add(sparkles);

    // --- Animation ---
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle diamond rotation
      diamond.rotation.y = t * 0.3;

      // Float
      diamond.position.y = Math.sin(t * 0.5) * 0.15;

      // Animate sparkles
      const pos = sparkles.geometry.attributes.position;
      for (let i = 0; i < sparkleCount; i++) {
        const v = sparkleVel[i];
        v.theta += v.speed * 0.01;
        pos.array[i * 3]     = Math.cos(v.theta) * v.r;
        pos.array[i * 3 + 1] = v.y + Math.sin(t * v.speed + v.phase) * 0.3;
        pos.array[i * 3 + 2] = Math.sin(v.theta) * v.r;
      }
      pos.needsUpdate = true;
      sparkleMat.opacity = 0.4 + Math.sin(t * 2) * 0.2;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // --- Resize ---
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
