**What's included:**

- **Scene** — a wall, floor, and fog for atmosphere
- **Door frame** — side jambs, header, and sill
- **Door leaf** — main panel with raised inset panels and stiles/rails for a classic look
- **Hardware** — hinges on the left side and a knob with a backplate
- **Lighting** — key light with soft shadows, a blue fill light, and ambient
- **Interaction** — **OrbitControls** (drag to rotate, scroll to zoom) and **Space** to toggle the door open/closed with smooth easing
- **Responsive** — handles window resizing

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Drum</title>
<style>
* { margin: 0; padding: 0; }
body { overflow: hidden; background: #111; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 25);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;

// --- Lighting ---
const ambLight = new THREE.AmbientLight(0x404060, 0.6);
scene.add(ambLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const rimLight = new THREE.PointLight(0x4466ff, 1.5, 15);
rimLight.position.set(-4, 2, -3);
scene.add(rimLight);

// --- Materials ---
const shellMat = new THREE.MeshStandardMaterial({
  color: 0x8b2500,
  roughness: 0.4,
  metalness: 0.1,
});

const headMat = new THREE.MeshStandardMaterial({
  color: 0xf5f0e8,
  roughness: 0.2,
  metalness: 0.0,
  transparent: true,
  opacity: 0.92,
});

const metalMat = new THREE.MeshStandardMaterial({
  color: 0xcccccc,
  roughness: 0.15,
  metalness: 0.9,
});

const hoopMat = new THREE.MeshStandardMaterial({
  color: 0xdddddd,
  roughness: 0.1,
  metalness: 0.95,
});

// --- Drum Group ---
const drum = new THREE.Group();
const RADIUS = 1.5;
const HEIGHT = 2.0;

// Shell (cylinder, open ends)
const shellGeo = new THREE.CylinderGeometry(RADIUS, RADIUS, HEIGHT, 48, 1, true);
const shell = new THREE.Mesh(shellGeo, shellMat);
shell.castShadow = true;
shell.receiveShadow = true;
drum.add(shell);

// Inner shell ring (bottom edge)
const innerRimGeo = new THREE.TorusGeometry(RADIUS, 0.04, 8, 48);
const innerRim = new THREE.Mesh(innerRimGeo, metalMat);
innerRim.rotation.x = Math.PI / 2;
innerRim.position.y = -HEIGHT / 2;
drum.add(innerRim);

// Top drumhead
const topHeadGeo = new THREE.CircleGeometry(RADIUS, 48);
const topHead = new THREE.Mesh(topHeadGeo, headMat);
topHead.rotation.x = -Math.PI / 2;
topHead.position.y = HEIGHT / 2 + 0.005;
topHead.receiveShadow = true;
drum.add(topHead);

// Bottom drumhead
const bottomHead = new THREE.Mesh(topHeadGeo, headMat);
bottomHead.rotation.x = Math.PI / 2;
bottomHead.position.y = -HEIGHT / 2 - 0.005;
bottomHead.receiveShadow = true;
drum.add(bottomHead);

// Top hoop (rim)
const hoopGeo = new THREE.TorusGeometry(RADIUS + 0.02, 0.06, 8, 48);
const hoop = new THREE.Mesh(hoopGeo, hoopMat);
hoop.rotation.x = Math.PI / 2;
hoop.position.y = HEIGHT / 2;
drum.add(hoop);

// Tension rods & lugs
const ROD_COUNT = 12;
for (let i = 0; i < ROD_COUNT; i++) {
  const angle = (i / ROD_COUNT) * Math.PI * 2;

  // Rod (vertical cylinder on the outside)
  const rodGeo = new THREE.CylinderGeometry(0.025, 0.025, HEIGHT + 0.2, 8);
  const rod = new THREE.Mesh(rodGeo, metalMat);
  rod.position.set(
    Math.cos(angle) * (RADIUS + 0.06),
    0,
    Math.sin(angle) * (RADIUS + 0.06)
  );
  drum.add(rod);

  // Lug (block on shell)
  const lugGeo = new THREE.BoxGeometry(0.18, 0.25, 0.12);
  const lug = new THREE.Mesh(lugGeo, metalMat);
  const lugR = RADIUS + 0.01;
  lug.position.set(
    Math.cos(angle) * lugR,
    HEIGHT / 2 - 0.15,
    Math.sin(angle) * lugR
  );
  lug.lookAt(0, HEIGHT / 2 - 0.15, 0);
  drum.add(lug);

  // Top nut (hex nut on rod)
  const nutGeo = new THREE.CylinderGeometry(0.04, 0.04, 0.06, 6);
  const nut = new THREE.Mesh(nutGeo, metalMat);
  nut.position.set(
    Math.cos(angle) * (RADIUS + 0.06),
    HEIGHT / 2 + 0.12,
    Math.sin(angle) * (RADIUS + 0.06)
  );
  drum.add(nut);
}

scene.add(drum);

// --- Floor ---
const floorGeo = new THREE.CircleGeometry(12, 48);
const floorMat = new THREE.MeshStandardMaterial({
  color: 0x111122,
  roughness: 0.8,
  metalness: 0.2,
});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -2.5;
floor.receiveShadow = true;
scene.add(floor);

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle bob
  drum.rotation.y = t * 0.15;
  drum.position.y = Math.sin(t * 0.8) * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **Cylindrical shell** in a warm rust/wood color
- **Two translucent drumheads** (top & bottom)
- **Chrome hoop** around the top edge
- **12 tension rods + lugs + nuts** evenly spaced around the shell
- **Three-point lighting** (ambient, directional with shadows, blue rim light)
- **OrbitControls** — click & drag to rotate, scroll to zoom
- **Gentle idle animation** — the drum slowly spins and bobs
- **Dark floor** with shadow reception

Just save it as `index.html` and open in any modern browser.

