    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(devicePixelRatio);
    renderer.shadowMap.enabled = true;
    document.body.appendChild(renderer.domElement);

    // ── Lighting ─────────────────────────────────────
    const ambient = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambient);

    const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
    sun.position.set(8, 15, 10);
    sun.castShadow = true;
    sun.shadow.mapSize.set(1024, 1024);
    scene.add(sun);

    // ── Flagpole ─────────────────────────────────────
    const poleGeo = new THREE.CylinderGeometry(0.08, 0.1, 12, 12);
    const poleMat = new THREE.MeshStandardMaterial({
      color: 0xcccccc, metalness: 0.8, roughness: 0.2
    });
    const pole = new THREE.Mesh(poleGeo, poleMat);
    pole.position.set(0, 6, 0);
    pole.castShadow = true;
    scene.add(pole);

    // Gold finial on top
    const finialGeo = new THREE.SphereGeometry(0.2, 16, 16);
    const finialMat = new THREE.MeshStandardMaterial({
      color: 0xffd700, metalness: 0.9, roughness: 0.15
    });
    const finial = new THREE.Mesh(finialGeo, finialMat);
    finial.position.set(0, 12.15, 0);
    finial.castShadow = true;
    scene.add(finial);

    // Base
    const baseGeo = new THREE.CylinderGeometry(0.6, 0.7, 0.3, 16);
    const baseMat = new THREE.MeshStandardMaterial({ color: 0x666666, roughness: 0.6 });
    const base = new THREE.Mesh(baseGeo, baseMat);
    base.position.set(0, 0.15, 0);
    base.castShadow = true;
    base.receiveShadow = true;
    scene.add(base);

    // ── Flag texture (French tricolour) ──────────────
    const flagCanvas = document.createElement('canvas');
    flagCanvas.width = 512;
    flagCanvas.height = 320;
    const ctx = flagCanvas.getContext('2d');

    // Blue
    ctx.fillStyle = '#002395';
    ctx.fillRect(0, 0, 170.67, 320);
    // White
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(170.67, 0, 170.67, 320);
    // Red
    ctx.fillStyle = '#ED2939';
    ctx.fillRect(341.33, 0, 170.67, 320);

    const flagTexture = new THREE.CanvasTexture(flagCanvas);
    flagTexture.colorSpace = THREE.SRGBColorSpace;

    // ── Flag geometry ────────────────────────────────
    const segmentsW = 60;
    const segmentsH = 30;
    const flagGeo = new THREE.PlaneGeometry(8, 5, segmentsW, segmentsH);

    // Shift geometry so pivot is at the pole edge
    flagGeo.translate(4, 0, 0);

    const flagMat = new THREE.MeshStandardMaterial({
      map: flagTexture,
      side: THREE.DoubleSide,
      roughness: 0.8,
      metalness: 0.0,
    });

    const flag = new THREE.Mesh(flagGeo, flagMat);
    flag.position.set(0, 10.5, 0);
    flag.castShadow = true;
    flag.receiveShadow = true;
    scene.add(flag);

    // ── Ground ───────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(30, 48);
    const groundMat = new THREE.MeshStandardMaterial({ color: 0x4a8c3f, roughness: 1 });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Waving animation ─────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      const positions = flagGeo.attributes.position;
      for (let i = 0; i < positions.count; i++) {
        const x = positions.getX(i);   // 0 at pole → 8 at tip
        const y = positions.getY(i);

        // Wave amplitude decreases toward the pole
        const distFromPole = x / 8;
        const wave = Math.sin(x * 1.8 - t * 3.5) * 0.4 * distFromPole
                   + Math.sin(x * 2.5 - t * 5.0) * 0.15 * distFromPole * distFromPole;

        positions.setZ(i, wave);
      }
      positions.needsUpdate = true;
      flagGeo.computeVertexNormals();

      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
