    shape.lineTo(Math.cos(a) * R, Math.sin(a) * R);
  }
  // Cutout (the notch)
  const holePath = new THREE.Path();
  const notchAngle = -0.3;
  const notchR = 1.8;
  holePath.moveTo(0, 0);
  holePath.lineTo(Math.cos(notchAngle - 0.25) * notchR, Math.sin(notchAngle - 0.25) * notchR);
  holePath.lineTo(Math.cos(notchAngle + 0.25) * notchR, Math.sin(notchAngle + 0.25) * notchR);
  holePath.lineTo(0, 0);
  shape.holes.push(holePath);

  const padGeo = new THREE.ShapeGeometry(shape, 32);
  const padMat = new THREE.MeshStandardMaterial({
    color: 0x2d7a3a,
    roughness: 0.7,
    metalness: 0.0,
    side: THREE.DoubleSide,
  });
  const pad = new THREE.Mesh(padGeo, padMat);
  pad.rotation.x = -Math.PI / 2;
  pad.position.y = 0.02;
  pad.castShadow = true;
  pad.receiveShadow = true;
  group.add(pad);

  // Veins on lily pad
  const veinMat = new THREE.LineBasicMaterial({ color: 0x1a5a28, transparent: true, opacity: 0.4 });
  for (let i = 0; i < 8; i++) {
    const angle = (i / 8) * Math.PI * 2;
    if (Math.abs(angle - notchAngle) < 0.4) continue;
    const points = [];
    points.push(new THREE.Vector3(0, 0.03, 0));
    for (let t = 0; t <= 1; t += 0.1) {
      const r = t * R * 0.9;
      points.push(new THREE.Vector3(Math.cos(angle) * r, 0.03, Math.sin(angle) * r));
    }
    const veinGeo = new THREE.BufferGeometry().setFromPoints(points);
    group.add(new THREE.Line(veinGeo, veinMat));
  }

  group.position.y = 0.0;
  return group;
}
scene.add(createLilyPad());

